import React, { useEffect, useMemo, useCallback, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getDepartments, deleteDepartment } from '../../../services/master.service';
import toast from 'react-hot-toast';

const DepartmentList = () => {
    const navigate = useNavigate();
    const [departments, setDepartments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchDepartments = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getDepartments({
                page,
                limit,
                search: searchQuery,
                include_inactive: true
            });

            setDepartments(response.departments || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch departments', err);
            toast.error(err.message || 'Failed to load departments');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchDepartments();
    }, [fetchDepartments]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;

        try {
            const ids = items.map(item => item.department_id);
            await Promise.all(ids.map(id => deleteDepartment(id)));
            toast.success('Department(s) deleted successfully');
            fetchDepartments();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete department');
        }
    };

    const columns = useMemo(
        () => [
            { key: 'department_code', header: 'Code', sortable: true },
            { key: 'department_name', header: 'Name (EN)', sortable: true },
            { key: 'department_name_mr', header: 'Name (MR)', sortable: true },
            { key: 'description', header: 'Description', sortable: true },
            {
                key: 'is_active',
                header: 'Status',
                render: (_, row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (_value, row, helpers) => (
                    <TableActions
                        onView={() => navigate(`/masters/departments/view/${row.department_id}`)}
                        onEdit={() => navigate(`/masters/departments/edit/${row.department_id}`)}
                        onDelete={() => helpers?.onDelete?.()}
                        viewPermission="masters.departments.view"
                        editPermission="masters.departments.edit"
                        deletePermission="masters.departments.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Departments"
                description="Manage department master data"
                actionLabel="Add Department"
                onAction={() => navigate('/masters/departments/add')}
                permission="masters.departments.create"
            />

            <DataTable
                columns={columns}
                data={departments}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="department_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default DepartmentList;
