import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button } from '../../../components/common/Button';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getPostById, createPost, updatePost, getSchemesWithTypes, getSchemeTypes, getDocumentTypes, getPostDocuments, updatePostDocuments, getEducationLevels, /* getCategories */ getExperienceDomains, getDistricts } from '../../../services/master.service';
import toast from 'react-hot-toast';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { Briefcase, Plus, Trash2 } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';
import DropdownSearch from '../../../components/common/DropdownSearch';

const PostForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    // Category selection temporarily disabled while APIs are offline
    // const selectAllCategoriesRef = useRef(null);

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(true);
    const [schemes, setSchemes] = useState([]);
    const [schemeTypes, setSchemeTypes] = useState([]);
    const [documentTypes, setDocumentTypes] = useState([]);
    const [selectedDocuments, setSelectedDocuments] = useState([]);
    const [educationLevels, setEducationLevels] = useState([]);
    const [districts, setDistricts] = useState([]);
    // const [categories, setCategories] = useState([]);
    const [experienceDomains, setExperienceDomains] = useState([]);
    const [globalMandatoryDocs, setGlobalMandatoryDocs] = useState([]);

    const [formData, setFormData] = useState({
        post_code: '',
        post_name: '',
        post_name_mr: '',
        description: '',
        description_mr: '',
        scheme_id: '',
        district_id: '',
        min_education_level_id: '',
        max_education_level_id: '',
        allowed_category_ids: [],
        min_qualification: '',
        min_experience_months: '',
        min_age: '',
        max_age: '',
        district_specific: false,
        female_only: false,
        male_only: false,
        required_domains: '',
        opening_date: '',
        closing_date: '',
        total_positions: '',
        experience_domain_id: '',
        amount: '',
        is_active: true
    });

    // const totalCategories = Array.isArray(categories) ? categories.length : 0;
    // const selectedCategoryIds = Array.isArray(formData.allowed_category_ids) ? formData.allowed_category_ids : [];
    // const isAllCategoriesSelected = totalCategories > 0 && selectedCategoryIds.length === totalCategories;
    // const isSomeCategoriesSelected = selectedCategoryIds.length > 0 && selectedCategoryIds.length < totalCategories;

    // useEffect(() => {
    //     if (selectAllCategoriesRef.current) {
    //         selectAllCategoriesRef.current.indeterminate = !isAllCategoriesSelected && isSomeCategoriesSelected;
    //     }
    // }, [isAllCategoriesSelected, isSomeCategoriesSelected]);

    // Load schemes when district changes
    useEffect(() => {
        const loadSchemes = async () => {
            try {
                const params = { is_active: true };
                if (formData.district_id) {
                    params.district_id = formData.district_id;
                }
                const [schemeRes, schemeTypeRes] = await Promise.all([
                    getSchemesWithTypes(params),
                    getSchemeTypes({ is_active: true })
                ]);
                const schemeList = Array.isArray(schemeRes) ? schemeRes : (schemeRes.schemes || []);
                const schemeTypeList = Array.isArray(schemeTypeRes) ? schemeTypeRes : (schemeTypeRes.schemeTypes || []);
                setSchemes(schemeList);
                setSchemeTypes(schemeTypeList);
            } catch (error) {
                console.error('Failed to load schemes', error);
            }
        };

        if (!fetching) {
            loadSchemes();
        }
    }, [formData.district_id, fetching]);

    useEffect(() => {
        const loadData = async () => {
            setFetching(true);
            try {
                // Load schemes and scheme types initially (will be reloaded when district changes)
                const [schemeRes, schemeTypeRes] = await Promise.all([
                    getSchemesWithTypes({ is_active: true }),
                    getSchemeTypes({ is_active: true })
                ]);
                const schemeList = Array.isArray(schemeRes) ? schemeRes : (schemeRes.schemes || []);
                const schemeTypeList = Array.isArray(schemeTypeRes) ? schemeTypeRes : (schemeTypeRes.schemeTypes || []);
                setSchemes(schemeList);
                setSchemeTypes(schemeTypeList);

                // Load districts
                const districtRes = await getDistricts({ is_active: true });
                const districtList = Array.isArray(districtRes) ? districtRes : (districtRes.districts || []);
                setDistricts(districtList);

                // Load document types
                const docTypesRes = await getDocumentTypes({ is_active: true });

                const docList = Array.isArray(docTypesRes) ? docTypesRes : (docTypesRes.documentTypes || []);

                setDocumentTypes(docList);

                // Load Education Levels
                const eduLevelsRes = await getEducationLevels({ is_active: true });
                setEducationLevels(Array.isArray(eduLevelsRes) ? eduLevelsRes : (eduLevelsRes.educationLevels || []));

                // Category APIs are disabled; skip loading until re-enabled
                // const catRes = await getCategories({ is_active: true });
                // setCategories(Array.isArray(catRes) ? catRes : (catRes.categories || []));

                // Load Experience Domains
                const expRes = await getExperienceDomains({ is_active: true });
                // Check for 'domains' key based on API response structure
                setExperienceDomains(Array.isArray(expRes) ? expRes : (expRes.domains || expRes.experienceDomains || []));

                // Filter Global Mandatory Documents
                const allDocs = Array.isArray(docTypesRes) ? docTypesRes : (docTypesRes.documentTypes || []);
                setGlobalMandatoryDocs(allDocs.filter(d => d.is_mandatory)); // Assuming is_mandatory flag exists

                if (isEditMode || isViewMode) {
                    const data = await getPostById(id);
                    setFormData({
                        post_code: data.post_code || '',
                        post_name: data.post_name_en || data.post_name || '',
                        post_name_mr: data.post_name_mr || '',
                        description: data.description_en || data.description || '',
                        description_mr: data.description_mr || '',
                        scheme_id: data.scheme_id || '',
                        district_id: data.district_id || '',
                        min_education_level_id: data.min_education_level_id || '',
                        max_education_level_id: data.max_education_level_id || '',
                        allowed_category_ids: data.allowed_category_ids || [],
                        min_qualification: data.min_qualification || '',
                        min_experience_months: data.min_experience_months ?? '',
                        min_age: data.min_age ?? '',
                        max_age: data.max_age ?? '',
                        district_specific: data.district_specific || false,
                        female_only: data.female_only === true,
                        male_only: data.male_only === true,
                        required_domains: data.required_domains || '',
                        opening_date: data.opening_date || '',
                        closing_date: data.closing_date || '',
                        total_positions: data.total_positions ?? '',
                        experience_domain_id: data.experience_domain_id || '',
                        amount: data.amount ?? '',
                        is_active: data.is_active
                    });

                    // Load existing documents for the post
                    try {
                        const docsData = await getPostDocuments(id);
                        // API returns array directly or wrapped in data/requirements
                        const requirements = Array.isArray(docsData) ? docsData : (docsData.requirements || docsData || []);
                        setSelectedDocuments(requirements.map(req => ({
                            doc_type_id: req.doc_type_id,
                            requirement_type: req.requirement_type || 'M',
                            mandatory_at_application: req.mandatory_at_application !== false
                        })));
                    } catch (err) {
                        console.warn('Failed to load post documents', err);
                        // Don't fail the whole page load if documents fail
                    }
                }
            } catch (error) {
                console.error('Failed to load data', error);
                toast.error('Failed to load form data');
                if (isEditMode || isViewMode) navigate('/masters/posts');
            } finally {
                setFetching(false);
            }
        };
        loadData();
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.post_code) {
            toast.error('Post Code is required');
            return;
        }
        if (!formData.post_name) {
            toast.error('Post Name is required');
            return;
        }
        // if (!formData.component_id) {
        //     toast.error('Component is required');
        //     return;
        // }

        setLoading(true);
        try {
            const payload = { ...formData };
            // Category API is disabled; avoid sending category payload for now
            delete payload.allowed_category_ids;
            // Convert numeric fields
            if (payload.min_experience_months) payload.min_experience_months = Number(payload.min_experience_months);
            if (payload.min_age) payload.min_age = Number(payload.min_age);
            if (payload.max_age) payload.max_age = Number(payload.max_age);
            if (payload.total_positions) payload.total_positions = Number(payload.total_positions);
            if (payload.amount) payload.amount = Number(payload.amount);

            if (payload.min_experience_months < 0) { toast.error('Experience cannot be negative'); setLoading(false); return; }
            if (payload.min_age < 0) { toast.error('Min Age cannot be negative'); setLoading(false); return; }
            if (payload.max_age < 0) { toast.error('Max Age cannot be negative'); setLoading(false); return; }
            if (payload.total_positions < 0) { toast.error('Total Positions cannot be negative'); setLoading(false); return; }

            if (payload.scheme_id !== '') payload.scheme_id = Number(payload.scheme_id);
            payload.district_id = payload.district_id === ''
                ? null
                : Number(payload.district_id);

            payload.min_education_level_id = payload.min_education_level_id === ''
                ? null
                : Number(payload.min_education_level_id);
            payload.max_education_level_id = payload.max_education_level_id === ''
                ? null
                : Number(payload.max_education_level_id);

            payload.experience_domain_id = payload.experience_domain_id === ''
                ? null
                : Number(payload.experience_domain_id);

            let postId = id;
            if (isEditMode) {
                await updatePost(id, payload);
                toast.success('Post updated successfully');
            } else {
                const newPost = await createPost(payload);
                postId = newPost.post_id || newPost.id; // Adjust based on actual response structure
                toast.success('Post created successfully');
            }

            // Save document requirements
            if (selectedDocuments.length > 0 || isEditMode) {
                try {
                    await updatePostDocuments(postId, {
                        requirements: selectedDocuments.map(d => ({
                            doc_type_id: Number(d.doc_type_id),
                            requirement_type: d.requirement_type,
                            mandatory_at_application: d.mandatory_at_application
                        }))
                    });
                } catch (docErr) {
                    console.error('Failed to save documents', docErr);
                    toast.error('Post saved but failed to update document requirements');
                }
            }

            navigate('/masters/posts');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save post');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <FormLayout
            title="Post"
            icon={Briefcase}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/posts')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <Input
                    label="Post Code"
                    value={formData.post_code}
                    onChange={(e) => setFormData(prev => ({ ...prev, post_code: e.target.value }))}
                    placeholder="e.g. OSC_CA"
                    required
                    disabled={isViewMode || isEditMode}
                />

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            District <span className="text-red-500">*</span>
                        </label>

                        <DropdownSearch
                            value={formData.district_id}
                            onChange={(e) =>
                                setFormData(prev => ({
                                    ...prev,
                                    district_id: e.target.value,
                                    scheme_id: ''
                                }))
                            }
                            options={districts.map(d => ({
                                id: d.district_id,
                                name: d.district_name
                            }))}
                            placeholder="Select District"
                        />

                        {!formData.district_id && (
                            <p className="text-xs text-amber-600 mt-1">
                                Please select a district first
                            </p>
                        )}
                    </div>
                <div>
    <label className="block text-sm font-medium text-slate-700 mb-1">
        Scheme
    </label>

                <DropdownSearch
                    value={formData.scheme_id}
                    onChange={(e) =>
                        setFormData(prev => ({
                            ...prev,
                            scheme_id: e.target.value
                        }))
                    }
                    options={Object.values(schemeTypes.reduce((acc, type) => {
                        acc[type.scheme_type_id] = {
                            ...type,
                            schemes: schemes.filter(scheme => scheme.scheme_type_id === type.scheme_type_id)
                        };
                        return acc;
                    }, {})).flatMap(type => 
                        type.schemes.map(scheme => ({
                            id: scheme.scheme_id,
                            name: `${scheme.scheme_name} (${type.scheme_name})`,
                            group: type.scheme_name
                        }))
                    )}
                    placeholder="Select Scheme"
                />

                {!formData.district_id && (
                    <p className="text-xs text-amber-600 mt-1">
                        Please select a district first
                    </p>
                )}
            </div>

                                
                <TransliteratedInput
                    label="Post Name"
                    value={formData.post_name}
                    onChange={(e) => setFormData(prev => ({ ...prev, post_name: e.target.value }))}
                    valueMr={formData.post_name_mr}
                    onChangeMr={(e) => setFormData(prev => ({ ...prev, post_name_mr: e.target.value }))}
                    placeholder="Center Administrator"
                    placeholderMr="केंद्र प्रशासक"
                    required
                    disabled={isViewMode}
                    manualTranslate
                    translateButtonLabel="Translate"
                    className="md:col-span-2"
                />

                {/* Min Qualification */}
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">
                        Min Qualification <span className="text-red-500">*</span>
                    </label>

                    <DropdownSearch
                        value={formData.min_education_level_id}
                        onChange={(e) =>
                            setFormData(prev => ({
                                ...prev,
                                min_education_level_id: e.target.value,
                                max_education_level_id:
                                    prev.max_education_level_id &&
                                    Number(prev.max_education_level_id) < Number(e.target.value)
                                        ? ''
                                        : prev.max_education_level_id
                            }))
                        }
                        options={educationLevels.map(l => ({
                            id: l.level_id,
                            name: l.level_name
                        }))}
                        placeholder="Select Level"
                    />
                </div>


                {/* Max Qualification */}
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-1">
                        Max Qualification <span className="text-red-500">*</span>
                    </label>

                    <DropdownSearch
                        value={formData.max_education_level_id}
                        onChange={(e) =>
                            setFormData(prev => ({
                                ...prev,
                                max_education_level_id: e.target.value
                            }))
                        }
                        options={educationLevels.map(l => ({
                            id: l.level_id,
                            name: l.level_name
                        }))}
                        placeholder="No Limit"
                    />
            </div>
                <Input
                    label="Min Experience (Months)"
                    type="number"
                    value={formData.min_experience_months}
                    onChange={(e) => setFormData(prev => ({ ...prev, min_experience_months: e.target.value }))}
                    placeholder="24"
                    min="0"
                    disabled={isViewMode}
                    required
                />

                <Input
                    label="Min Age"
                    type="number"
                    value={formData.min_age}
                    onChange={(e) => setFormData(prev => ({ ...prev, min_age: e.target.value }))}
                    placeholder="21"
                    min="0"
                    disabled={isViewMode}
                    required
                />

                <Input
                    label="Max Age"
                    type="number"
                    value={formData.max_age}
                    onChange={(e) => setFormData(prev => ({ ...prev, max_age: e.target.value }))}
                    placeholder="45"
                    min="0"
                    disabled={isViewMode}
                />

                <Input
                    label="Opening Date"
                    type="date"
                    value={formData.opening_date}
                    onChange={(e) => {
                        const newOpen = e.target.value;
                        setFormData(prev => {
                                    // If closing date exists and is not after opening date, clear it
                            let newClose = prev.closing_date;
                                    if (newClose && newClose <= newOpen) {
                                        newClose = ''; // Reset closing date if not after opening date
                                    }
                            return { ...prev, opening_date: newOpen, closing_date: newClose };
                                })
                    }}
                    disabled={isViewMode}
                            // required
                />

                <Input
                    label="Closing Date"
                    type="date"
                    value={formData.closing_date}
                            min={formData.opening_date ? new Date(new Date(formData.opening_date).getTime() + 86400000).toISOString().split('T')[0] : ''} // Enforce min date as day after opening
                    onChange={(e) => setFormData(prev => ({ ...prev, closing_date: e.target.value }))}
                    disabled={isViewMode || !formData.opening_date}
                            // required
                />

                <Input
                    label="Total Positions"
                    type="number"
                    value={formData.total_positions}
                    onChange={(e) => setFormData(prev => ({ ...prev, total_positions: e.target.value }))}
                    placeholder="10"
                    min="0"
                    disabled={isViewMode}
                />

                <Input
                    label="Amount"
                    type="number"
                    value={formData.amount}
                    onChange={(e) => setFormData(prev => ({ ...prev, amount: e.target.value }))}
                    placeholder="24000.00"
                    min="0"
                    // step="0.01"
                    disabled={isViewMode}
                />

            <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                    Required Experience Domain
                </label>

                <DropdownSearch
                    value={formData.experience_domain_id}
                    onChange={(e) =>
                        setFormData(prev => ({
                            ...prev,
                            experience_domain_id: e.target.value
                        }))
                    }
                    options={experienceDomains.map(domain => ({
                        id: domain.domain_id,
                        name: domain.domain_name
                    }))}
                    placeholder="Select Experience Domain"
                />
            </div>
                {/* Gender Eligibility */}
                <div className="md:col-span-2">
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                Gender Eligibility
                            </label>
                    <div className="flex gap-6">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={formData.female_only}
                                onChange={(e) => setFormData(prev => ({
                                    ...prev,
                                    female_only: e.target.checked,
                                    male_only: e.target.checked ? false : prev.male_only
                                }))}
                                disabled={isViewMode}
                                className="w-4 h-4 text-blue-600 border-slate-300 rounded focus:ring-blue-500"
                            />
                            <span className="text-sm text-slate-700">Female Only</span>
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={formData.male_only}
                                onChange={(e) => setFormData(prev => ({
                                    ...prev,
                                    male_only: e.target.checked,
                                    female_only: e.target.checked ? false : prev.female_only
                                }))}
                                disabled={isViewMode}
                                className="w-4 h-4 text-blue-600 border-slate-300 rounded focus:ring-blue-500"
                            />
                            <span className="text-sm text-slate-700">Male Only</span>
                        </label>
                    </div>
                    {!formData.female_only && !formData.male_only && (
                        <p className="text-xs text-slate-500 mt-1">Post is open for all genders</p>
                    )}
                </div>
            </div>

            {/* Description */}
            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Enter description..."
                placeholderMr="मराठी वर्णन"
                isTextArea
                disabled={isViewMode}
                manualTranslate
                translateButtonLabel="Translate"
            />

            {/* Active Status Toggle */}
            <ToggleSwitch
                label="Active Status"
                description={formData.is_active ? 'Post is currently active' : 'Post is currently inactive'}
                checked={formData.is_active}
                onChange={(checked) => setFormData(prev => ({ ...prev, is_active: checked }))}
                disabled={isViewMode}
            />

            {/* Document Requirements */}
            <div className="border-t border-slate-100 pt-2">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="text-sm font-semibold text-slate-700">Document Requirements</h3>
                    {!isViewMode && (
                        <Button
                            type="button"
                            variant="outline"
                            size="sm"
                            onClick={() => setSelectedDocuments([...selectedDocuments, { doc_type_id: '', requirement_type: 'M', mandatory_at_application: true }])}
                            leftIcon={<Plus className="h-4 w-4" />}
                        >
                            Add Document
                        </Button>
                    )}
                </div>

                <div className="space-y-3">
                    {selectedDocuments.length === 0 && (
                        <p className="text-sm text-slate-500 italic">No document requirements added.</p>
                    )}

                    {selectedDocuments.map((doc, index) => (
                        <div key={index} className="flex flex-col md:flex-row gap-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
                            <div className="flex-1">
                                <label className="block text-xs font-medium text-slate-500 mb-1">Document Type</label>
                                <select
                                    value={doc.doc_type_id}
                                    onChange={(e) => {
                                        const newDocs = [...selectedDocuments];
                                        newDocs[index].doc_type_id = e.target.value;
                                        setSelectedDocuments(newDocs);
                                    }}
                                    className="w-full rounded-xl border border-slate-200 bg-white px-4 py-2.5 text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
                                    disabled={isViewMode}
                                    required
                                >
                                    <option value="">Select Document</option>
                                    {documentTypes.map(dt => (
                                        <option key={dt.doc_type_id} value={dt.doc_type_id}>{dt.doc_type_name}</option>
                                    ))}
                                </select>
                            </div>

                            <div className="flex items-center gap-6 mt-2 md:mt-0">
                                <div className="flex items-center gap-2">
                                    <input
                                        type="checkbox"
                                        id={`req_${index}`}
                                        checked={doc.requirement_type === 'M'}
                                        onChange={(e) => {
                                            const newDocs = [...selectedDocuments];
                                            newDocs[index].requirement_type = e.target.checked ? 'M' : 'O';
                                            setSelectedDocuments(newDocs);
                                        }}
                                        className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                                        disabled={isViewMode}
                                    />
                                    <label htmlFor={`req_${index}`} className="text-sm font-medium text-slate-700">Mandatory</label>
                                </div>

                                {!isViewMode && (
                                    <Button
                                        type="button"
                                        variant="ghost"
                                        size="sm"
                                        className="text-red-500 hover:text-red-700 hover:bg-red-50"
                                        onClick={() => {
                                            const newDocs = [...selectedDocuments];
                                            newDocs.splice(index, 1);
                                            setSelectedDocuments(newDocs);
                                        }}
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </FormLayout>
    );
};

export default PostForm;