import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getEducationLevelById, createEducationLevel, updateEducationLevel, getDocumentTypes } from '../../../services/master.service';
import toast from 'react-hot-toast';
import { GraduationCap } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';
import ToggleSwitch from '../../../components/common/ToggleSwitch';

const EducationLevelForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;
    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);
    const [documentTypes, setDocumentTypes] = useState([]);

    const [formData, setFormData] = useState({
        level_code: '',
        level_name: '',
        level_name_mr: '',
        description: '',
        description_mr: '',
        display_order: '',
        document_type_id: '',
        is_active: true
    });

    useEffect(() => {
        const fetchDocumentTypes = async () => {
            try {
                const response = await getDocumentTypes({ include_inactive: false });
                setDocumentTypes(response.documentTypes || []);
            } catch (error) {
                console.error('Failed to fetch document types', error);
                toast.error('Failed to load document types');
            }
        };
        fetchDocumentTypes();
    }, []);

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchLevel = async () => {
                setFetching(true);
                try {
                    const data = await getEducationLevelById(id);
                    setFormData({
                        level_code: data.level_code || '',
                        level_name: data.level_name_en || data.level_name || '',
                        level_name_mr: data.level_name_mr || '',
                        description: data.description_en || data.description || '',
                        description_mr: data.description_mr || '',
                        display_order: data.display_order || '',
                        document_type_id: data.doc_type_id || '', // Backend uses doc_type_id
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch education level', error);
                    toast.error('Failed to load education level details');
                    navigate('/masters/education-levels');
                } finally {
                    setFetching(false);
                }
            };
            fetchLevel();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.level_code || !formData.level_name) {
            toast.error('Code and Name are required');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            if (payload.display_order) {
                payload.display_order = Number(payload.display_order);
                if (payload.display_order < 0) {
                    toast.error('Display Order cannot be negative');
                    setLoading(false);
                    return;
                }
            }

            // Convert doc_type_id: empty string to null, otherwise to number
            if (payload.document_type_id === '' || payload.document_type_id === null) {
                payload.doc_type_id = null;
            } else {
                payload.doc_type_id = Number(payload.document_type_id);
            }
            delete payload.document_type_id; // Remove the frontend field name

            if (isEditMode) {
                await updateEducationLevel(id, payload);
                toast.success('Education level updated successfully');
            } else {
                await createEducationLevel(payload);
                toast.success('Education level created successfully');
            }
            navigate('/masters/education-levels');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save education level');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) return <div className="p-8 text-center text-slate-500">Loading...</div>;

    return (
        <FormLayout
            title="Education Level"
            icon={GraduationCap}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/education-levels')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <Input
                label="Level Code"
                value={formData.level_code}
                onChange={(e) => setFormData(prev => ({ ...prev, level_code: e.target.value }))}
                placeholder="GRADUATE"
                required
                disabled={isViewMode || isEditMode}
            />
            <TransliteratedInput
                label="Level Name"
                value={formData.level_name}
                onChange={(e) => setFormData(prev => ({ ...prev, level_name: e.target.value }))}
                valueMr={formData.level_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, level_name_mr: e.target.value }))}
                placeholder="Graduate (Bachelor's Degree)"
                placeholderMr="पदवीधर"
                disabled={isViewMode}
                required
                manualTranslate
                translateButtonLabel="Translate"
            />

            <Input
                label="Display Order"
                type="number"
                value={formData.display_order}
                onChange={(e) => setFormData(prev => ({ ...prev, display_order: e.target.value }))}
                placeholder="30"
                min="0"
                required
                disabled={isViewMode}
            />
            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Enter description..."
                placeholderMr="मराठी वर्णन"
                isTextArea
                disabled={isViewMode}
                manualTranslate
                translateButtonLabel="Translate"
            />

            <ToggleSwitch
                    label="Active Status"
                    description={formData.is_active ? 'Education level is currently active' : 'Education level is currently inactive'}
                    checked={formData.is_active}
                    onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                    disabled={isViewMode}
                    />
        </FormLayout>
    );
};

export default EducationLevelForm;