import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getSchemes, createScheme, updateScheme, getSchemeById, getSchemeTypes } from '../../../services/master.service';
import { getDistricts } from '../../../services/master.service';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import DropdownSearch from '../../../components/common/DropdownSearch';
import FormLayout from '../../../components/common/FormLayout';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { Building2 } from 'lucide-react';
import toast from 'react-hot-toast';

const SchemeForm = ({ isViewMode = false }) => {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEditMode = Boolean(id) && !isViewMode;
  const isViewing = Boolean(id) && isViewMode;

  const [formData, setFormData] = useState({
    scheme_code: '',
    scheme_name: '',
    scheme_name_mr: '',
    scheme_type_id: '',
    description: '',
    description_mr: '',
    district_id: '',
    latitude: '',
    longitude: '',
    geofence_radius_meters: '',
    is_active: true
  });

  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(isEditMode || isViewing);
  const [districts, setDistricts] = useState([]);
  const [schemeTypes, setSchemeTypes] = useState([]);

  const fetchDistricts = useCallback(async () => {
    try {
      const response = await getDistricts({ is_active: true });
      const districtList = Array.isArray(response)
        ? response
        : response.districts || [];
      setDistricts(districtList);
    } catch (err) {
      toast.error('Failed to load districts');
    }
  }, []);

  const fetchSchemeTypes = useCallback(async () => {
    try {
      const response = await getSchemeTypes({ is_active: true });
      const schemeTypeList = Array.isArray(response)
        ? response
        : response.schemeTypes || [];
      setSchemeTypes(schemeTypeList);
    } catch (err) {
      toast.error('Failed to load scheme types');
    }
  }, []);

  const fetchScheme = useCallback(async () => {
    if (!id) return;
    
    try {
      const data = await getSchemeById(id);
      setFormData({
        scheme_code: data.scheme_code || '',
        scheme_name: data.scheme_name || '',
        scheme_name_mr: data.scheme_name_mr || '',
        scheme_type_id: data.scheme_type_id ? String(data.scheme_type_id) : '',
        description: data.description || '',
        description_mr: data.description_mr || '',
        district_id: data.district_id ? String(data.district_id) : '',
        latitude: data.latitude || '',
        longitude: data.longitude || '',
        geofence_radius_meters: data.geofence_radius_meters || '',
        is_active: data.is_active !== undefined ? data.is_active : true,
      });
    } catch (error) {
      console.error("Failed to load scheme form data", error);
      const errorMessage =
        error.response?.data?.message ||
        error.message ||
        "Failed to load scheme details";
      toast.error(errorMessage);
      if (isEditMode || isViewing) {
        navigate("/masters/schemes");
      }
    }
  }, [id, isEditMode, isViewing, navigate]);

  useEffect(() => {
    const loadData = async () => {
      setFetching(true);
      try {
        // Load districts and scheme types
        await Promise.all([
          fetchDistricts(),
          fetchSchemeTypes()
        ]);

        if (isEditMode || isViewMode) {
          await fetchScheme();
        }
      } catch (error) {
        console.error("Failed to load form data", error);
        toast.error("Failed to load form data");
        if (isEditMode || isViewMode) {
          navigate("/masters/schemes");
        }
      } finally {
        setFetching(false);
      }
    };

    loadData();
  }, [id, isEditMode, isViewMode, navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.scheme_code) {
      toast.error("Scheme Code is required");
      return;
    }
    if (!formData.scheme_name) {
      toast.error("Scheme Name is required");
      return;
    }
    if (!formData.scheme_type_id) {
      toast.error("Scheme Type is required");
      return;
    }
    if (!formData.district_id) {
      toast.error("District is required");
      return;
    }

    setLoading(true);
    try {
      const payload = { ...formData };
      payload.district_id =
        payload.district_id === "" ? null : Number(payload.district_id);
      payload.scheme_type_id =
        payload.scheme_type_id === "" ? null : Number(payload.scheme_type_id);
      payload.latitude =
        payload.latitude !== "" ? Number(payload.latitude) : null;
      payload.longitude =
        payload.longitude !== "" ? Number(payload.longitude) : null;
      payload.geofence_radius_meters =
        payload.geofence_radius_meters !== ""
          ? Number(payload.geofence_radius_meters)
          : null;

      if (isEditMode) {
        await updateScheme(id, payload);
        toast.success("Scheme updated successfully");
      } else {
        await createScheme(payload);
        toast.success("Scheme created successfully");
      }

      navigate("/masters/schemes");
    } catch (error) {
      console.error("Save failed", error);
      toast.error(error.message || "Failed to save scheme");
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: field === 'is_active' ? value : value
    }));
    
    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  if (fetching) {
    return <div className="p-8 text-center text-slate-500">Loading...</div>;
  }

  return (
    <FormLayout
      title="Scheme"
      icon={Building2}
      onSubmit={handleSubmit}
      onCancel={() => navigate("/masters/schemes")}
      isEditMode={isEditMode}
      isViewMode={isViewing}
      loading={loading}
    >
      <Input
        label="Scheme Code"
        value={formData.scheme_code}
        onChange={(e) =>
          setFormData((prev) => ({ ...prev, scheme_code: e.target.value.toUpperCase() }))
        }
        placeholder="e.g. OSC_Latur"
        required
        disabled={isViewing || isEditMode}
      />

      <TransliteratedInput
        label="Scheme Name"
        value={formData.scheme_name}
        onChange={(e) =>
          setFormData((prev) => ({ ...prev, scheme_name: e.target.value }))
        }
        valueMr={formData.scheme_name_mr}
        onChangeMr={(e) =>
          setFormData((prev) => ({ ...prev, scheme_name_mr: e.target.value }))
        }
        placeholder="e.g. One Stop Centre - Latur"
        placeholderMr="वन स्टॉप सेंटर - लातूर"
        required
        disabled={isViewing}
        manualTranslate
        translateButtonLabel="Translate"
      />

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-1">
          Scheme Type
        </label>
        <DropdownSearch
          value={formData.scheme_type_id}
          onChange={(e) =>
            setFormData((prev) => ({ ...prev, scheme_type_id: e.target.value }))
          }
          options={schemeTypes.map((type) => ({
            id: type.scheme_type_id,
            name: type.scheme_name,
            name_mr: type.scheme_name_mr,
          }))}
          placeholder="Select Scheme Type"
          disabled={isViewing}
        />
      </div>

      <div>
        <label className="block text-sm font-semibold text-slate-700 mb-1">
          District
        </label>
        <DropdownSearch
          value={formData.district_id}
          onChange={(e) =>
            setFormData((prev) => ({ ...prev, district_id: e.target.value }))
          }
          options={districts.map((d) => ({
            id: d.district_id,
            name: d.district_name,
            name_mr: d.district_name_mr,
          }))}
          placeholder="Select District"
          disabled={isViewing}
        />
      </div>

      <TransliteratedInput
        label="Description"
        value={formData.description}
        onChange={(e) =>
          setFormData((prev) => ({ ...prev, description: e.target.value }))
        }
        valueMr={formData.description_mr}
        onChangeMr={(e) =>
          setFormData((prev) => ({ ...prev, description_mr: e.target.value }))
        }
        placeholder="Enter description..."
        placeholderMr="वर्णन प्रविष्ट करा..."
        isTextArea
        disabled={isViewing}
      />

      <div className="grid grid-cols-12 gap-4">
        <div className="col-span-6">
          <Input
            label="Latitude"
            value={formData.latitude}
            onChange={(e) =>
              setFormData((prev) => ({ ...prev, latitude: e.target.value }))
            }
            placeholder="e.g. 18.409617"
          />
        </div>

        <div className="col-span-6">
          <Input
            label="Longitude"
            value={formData.longitude}
            onChange={(e) =>
              setFormData((prev) => ({ ...prev, longitude: e.target.value }))
            }
            placeholder="e.g. 76.535522"
          />
        </div>

        <div className="col-span-6">
          <Input
            label="Geofence Radius (meters)"
            value={formData.geofence_radius_meters}
            onChange={(e) =>
              setFormData((prev) => ({
                ...prev,
                geofence_radius_meters: e.target.value,
              }))
            }
            placeholder="e.g. 100"
          />
        </div>
      </div>

      <ToggleSwitch
        label="Active Status"
        description={
          formData.is_active
            ? "Scheme is currently active"
            : "Scheme is currently inactive"
        }
        checked={formData.is_active}
        onChange={(val) => setFormData((prev) => ({ ...prev, is_active: val }))}
        disabled={isViewing}
      />
    </FormLayout>
  );
};

export default SchemeForm;
