import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getDepartmentById, createDepartment, updateDepartment } from '../../../services/master.service';
import toast from 'react-hot-toast';
import { Building } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';
import ToggleSwitch from '../../../components/common/ToggleSwitch';

const DepartmentForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);

    const [formData, setFormData] = useState({
        department_code: '',
        department_name: '',
        department_name_mr: '',
        description: '',
        description_mr: '',
        is_active: true
    });

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchDepartment = async () => {
                setFetching(true);
                try {
                    const data = await getDepartmentById(id);
                    setFormData({
                        department_code: data.department_code || '',
                        department_name: data.department_name_en || data.department_name || '',
                        department_name_mr: data.department_name_mr || '',
                        description: data.description || '',
                        description_mr: data.description_mr || '',
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch department', error);
                    toast.error('Failed to load department details');
                    navigate('/masters/departments');
                } finally {
                    setFetching(false);
                }
            };
            fetchDepartment();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.department_code) {
            toast.error('Department Code is required');
            return;
        }
        if (!formData.department_name) {
            toast.error('Department Name is required');
            return;
        }

        setLoading(true);
        try {
            if (isEditMode) {
                await updateDepartment(id, formData);
                toast.success('Department updated successfully');
            } else {
                await createDepartment(formData);
                toast.success('Department created successfully');
            }
            navigate('/masters/departments');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save department');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <FormLayout
            title="Department"
            icon={Building}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/departments')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <Input
                label="Department Code"
                value={formData.department_code}
                onChange={(e) => setFormData(prev => ({ ...prev, department_code: e.target.value }))}
                placeholder="e.g. DWCD"
                required
                disabled={isEditMode || isViewMode}
            />

            <TransliteratedInput
                label="Department Name"
                value={formData.department_name}
                onChange={(e) => setFormData(prev => ({ ...prev, department_name: e.target.value }))}
                valueMr={formData.department_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, department_name_mr: e.target.value }))}
                placeholder="Women and Child Development"
                placeholderMr="महिला आणि बाल विकास विभाग"
                disabled={isViewMode}
                required
            />

            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Describe department roles..."
                placeholderMr="विभागाची भूमिका..."
                isTextArea
                disabled={isViewMode}
            />

            <ToggleSwitch
                    label="Active Status"
                    description={formData.is_active ? 'Department is currently active' : 'Department is currently inactive'}
                    checked={formData.is_active}
                    onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                    disabled={isViewMode}
                />
        </FormLayout>
    );
};

export default DepartmentForm;