import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { Switch } from '../../../components/common/Switch';
import { MediaViewer } from '../../../components/common/MediaViewer';
import { PermissionGuard } from '../../../components/auth/PermissionGuard';
import { getBanners, deleteBanner, updateBanner } from '../../../services/master.service';
import toast from 'react-hot-toast';

const BannerList = () => {
  const navigate = useNavigate();
  const [banners, setBanners] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const fetchBanners = useCallback(async () => {
    setLoading(true);
    try {
      const response = await getBanners({
        page,
        limit,
        search: searchQuery,
        include_inactive: true
      });
      setBanners(response.banners || []);
      setTotalPages(response.pagination?.totalPages || 1);
      setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
    } catch (error) {
      console.error('Failed to fetch banners', error);
      toast.error(error.message || 'Failed to load banners');
    } finally {
      setLoading(false);
    }
  }, [page, limit, searchQuery]);

  useEffect(() => {
    fetchBanners();
  }, [fetchBanners]);

  const handleDelete = async (items) => {
    if (!items || items.length === 0) return;
    try {
      await Promise.all(items.map((item) => deleteBanner(item.banner_id)));
      toast.success('Banner(s) deleted successfully');
      fetchBanners();
    } catch (error) {
      console.error('Delete failed', error);
      toast.error(error.message || 'Failed to delete banner');
    }
  };

  const handleToggleActive = async (banner, checked) => {
    try {
      // Optimistic update
      setBanners(prev => prev.map(b => b.banner_id === banner.banner_id ? { ...b, is_active: checked } : b));

      await updateBanner(banner.banner_id, { is_active: checked });
      toast.success(`Banner ${checked ? 'activated' : 'deactivated'} successfully`);
    } catch (error) {
      console.error('Toggle active failed', error);
      toast.error(error.message || 'Failed to update status');
      // Revert on failure
      setBanners(prev => prev.map(b => b.banner_id === banner.banner_id ? { ...b, is_active: !checked } : b));
    }
  };

  const columns = useMemo(
    () => [
      {
        key: 'banner_image_path',
        header: 'Image (EN)',
        render: (_, row) =>
          row.banner_image_path ? (
            <MediaViewer
              src={`/${row.banner_image_path}`}
              alt="Banner (English)"
              variant="button"
              className="inline-flex"
            />
          ) : (
            <span className="text-xs text-slate-400">No image</span>
          )
      },
      {
        key: 'banner_image_path_mr',
        header: 'Image (MR)',
        render: (_, row) =>
          row.banner_image_path_mr ? (
            <MediaViewer
              src={`/${row.banner_image_path_mr}`}
              alt="Banner (Marathi)"
              variant="button"
              className="inline-flex"
            />
          ) : (
            <span className="text-xs text-slate-400">Not set</span>
          )
      },
      {
        key: 'display_order',
        header: 'Order',
        sortable: true
      },
      {
        key: 'is_active',
        header: 'Status',
        className: 'text-center',
        render: (_, row) => (
          <div className="flex items-center justify-center gap-2">
            <PermissionGuard permissions="masters.banners.edit">
              <Switch
                checked={row.is_active}
                onCheckedChange={(checked) => handleToggleActive(row, checked)}
              />
            </PermissionGuard>
            <span className={`text-xs ${row.is_active ? 'text-green-600' : 'text-slate-500'}`}>
              {row.is_active ? 'Active' : 'Inactive'}
            </span>
          </div>
        )
      },
      {
        key: 'actions',
        header: 'Actions',
        render: (_value, row, helpers) => (
          <TableActions
            onView={() => navigate(`/masters/banners/view/${row.banner_id}`)}
            onEdit={() => navigate(`/masters/banners/edit/${row.banner_id}`)}
            onDelete={() => helpers?.onDelete?.()}
            viewPermission="masters.banners.view"
            editPermission="masters.banners.edit"
            deletePermission="masters.banners.delete"
          />
        )
      }
    ],
    [navigate]
  );

  return (
    <div className="space-y-6">
      <PageHeader
        title="Banners"
        description="Manage banner images for the public site"
        actionLabel="Add Banner"
        onAction={() => navigate('/masters/banners/add')}
        permission="masters.banners.create"
      />

      <DataTable
        columns={columns}
        data={banners}
        onSearch={setSearchQuery}
        showRowNumbers={true}
        onDelete={handleDelete}
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50, 100]
        }}
        isLoading={loading}
        rowKey="banner_id"
        headerClassName="bg-slate-900 text-white"
      />
    </div>
  );
};

export default BannerList;
