import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getDocumentTypes, deleteDocumentType } from '../../../services/master.service';
import toast from 'react-hot-toast';

const DocumentTypeList = () => {
    const navigate = useNavigate();
    const [documentTypes, setDocumentTypes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchDocumentTypes = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getDocumentTypes({ page, limit, search: searchQuery, include_inactive: true });
            setDocumentTypes(response.documentTypes || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch document types', err);
            toast.error(err.message || 'Failed to load document types');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchDocumentTypes();
    }, [fetchDocumentTypes]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;
        try {
            await Promise.all(items.map(item => deleteDocumentType(item.doc_type_id)));
            toast.success('Document type(s) deleted successfully');
            fetchDocumentTypes();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete document type');
        }
    };

    const columns = useMemo(() => [
        { key: 'doc_type_code', header: 'Code', sortable: true },
        { key: 'doc_type_name', header: 'Name (EN)', sortable: true },
        {
            key: 'is_mandatory',
            header: 'Mandatory',
            render: (_, row) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_mandatory ? 'bg-blue-50 text-blue-700' : 'bg-gray-50 text-gray-700'}`}>
                    {row.is_mandatory ? 'Yes' : 'No'}
                </span>
            )
        },
        // { key: 'allowed_formats', header: 'Formats' },
        // { key: 'max_size_mb', header: 'Max Size (MB)' },
        {
            key: 'is_active',
            header: 'Status',
            render: (_, row) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                    {row.is_active ? 'Active' : 'Inactive'}
                </span>
            )
        },
        {
            key: 'actions',
            header: 'Actions',
            render: (_value, row, helpers) => (
                <TableActions
                    onView={() => navigate(`/masters/document-types/view/${row.doc_type_id}`)}
                    onEdit={() => navigate(`/masters/document-types/edit/${row.doc_type_id}`)}
                    onDelete={() => helpers?.onDelete?.()}
                    viewPermission="masters.document_types.view"
                    editPermission="masters.document_types.edit"
                    deletePermission="masters.document_types.delete"
                />
            ),
        },
    ], [navigate]);

    return (
        <div className="space-y-6">
            <PageHeader
                title="Document Types"
                description="Manage document types master data"
                actionLabel="Add Document Type"
                onAction={() => navigate('/masters/document-types/add')}
                permission="masters.document_types.create"
            />
            <DataTable
                columns={columns}
                data={documentTypes}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="doc_type_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default DocumentTypeList;
