import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getSchemeTypeById, createSchemeType, updateSchemeType } from '../../../services/master.service';
import toast from 'react-hot-toast';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { Layers } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';

const SchemeTypeForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(true);

    const [formData, setFormData] = useState({
        scheme_code: '',
        scheme_name: '',
        scheme_name_mr: '',
        description: '',
        description_mr: '',
        is_active: true
    });

    useEffect(() => {
        const loadData = async () => {
            setFetching(true);
            try {
                if (isEditMode || isViewMode) {
                    const data = await getSchemeTypeById(id);
                    setFormData({
                        scheme_code: data.scheme_code || '',
                        scheme_name: data.scheme_name || '',
                        scheme_name_mr: data.scheme_name_mr || '',
                        description: data.description || '',
                        description_mr: data.description_mr || '',
                        is_active: data.is_active !== undefined ? data.is_active : true
                    });
                }
            } catch (error) {
                console.error('Failed to load data', error);
                toast.error('Failed to load scheme type data');
                navigate('/masters/scheme-types');
            } finally {
                setFetching(false);
            }
        };
        loadData();
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.scheme_code) {
            toast.error('Scheme Code is required');
            return;
        }
        if (!formData.scheme_name) {
            toast.error('Scheme Name is required');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };

            if (isEditMode) {
                await updateSchemeType(id, payload);
                toast.success('Scheme type updated successfully');
            } else {
                await createSchemeType(payload);
                toast.success('Scheme type created successfully');
            }

            navigate('/masters/scheme-types');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save scheme type');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <FormLayout
            title="Scheme Type"
            icon={Layers}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/scheme-types')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <Input
                label="Scheme Code"
                value={formData.scheme_code}
                onChange={(e) => setFormData(prev => ({ ...prev, scheme_code: e.target.value.toUpperCase() }))}
                placeholder="e.g. OSC, HUB, 181"
                required
                disabled={isViewMode || isEditMode}
            />

            <TransliteratedInput
                label="Scheme Type Name"
                value={formData.scheme_name}
                onChange={(e) => setFormData(prev => ({ ...prev, scheme_name: e.target.value }))}
                valueMr={formData.scheme_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, scheme_name_mr: e.target.value }))}
                placeholder="e.g. One Stop Center"
                placeholderMr="वन स्टॉप सेंटर"
                required
                disabled={isViewMode}
                manualTranslate
                translateButtonLabel="Translate"
            />

            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Optional description"
                placeholderMr="वैकल्पिक वर्णन"
                isTextArea
                disabled={isViewMode}
            />

            <ToggleSwitch
                label="Active Status"
                description={formData.is_active ? 'Scheme type is currently active' : 'Scheme type is currently inactive'}
                checked={formData.is_active}
                onChange={(checked) => setFormData(prev => ({ ...prev, is_active: checked }))}
                disabled={isViewMode}
            />
        </FormLayout>
    );
};

export default SchemeTypeForm;
