import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { MapPin } from "lucide-react";
import FormLayout from "../../../components/common/FormLayout";
import { TransliteratedInput } from "../../../components/common/TransliteratedInput";
import {
  getDistrictById,
  createDistrict,
  updateDistrict,
} from "../../../services/master.service";
import toast from "react-hot-toast";
import ToggleSwitch from '../../../components/common/ToggleSwitch';

const DistrictForm = ({ isViewMode = false }) => {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = !!id;

  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(isEditMode || isViewMode);

  const [formData, setFormData] = useState({
    district_name: "",
    district_name_mr: "",
    is_active: true,
  });

  useEffect(() => {
    if (isEditMode || isViewMode) {
      const fetchDistrict = async () => {
        setFetching(true);
        try {
          const data = await getDistrictById(id);
          setFormData({
            district_name: data.district_name_en || data.district_name,
            district_name_mr: data.district_name_mr || "",
            is_active: data.is_active,
          });
        } catch (error) {
          console.error("Failed to fetch district", error);
          toast.error("Failed to load district details");
          navigate("/masters/districts");
        } finally {
          setFetching(false);
        }
      };
      fetchDistrict();
    }
  }, [id, isEditMode, isViewMode, navigate]);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.district_name) {
      toast.error("District Name is required");
      return;
    }

    setLoading(true);
    try {
      if (isEditMode) {
        await updateDistrict(id, formData);
        toast.success("District updated successfully");
      } else {
        await createDistrict(formData);
        toast.success("District created successfully");
      }
      navigate("/masters/districts");
    } catch (error) {
      console.error("Save failed", error);
      toast.error(error.message || "Failed to save district");
    } finally {
      setLoading(false);
    }
  };

  if (fetching) return <div className="text-center py-20">Loading...</div>;

  return (
    <FormLayout
      title="District"
      icon={MapPin}
      onSubmit={handleSubmit}
      onCancel={() => navigate("/masters/districts")}
      isEditMode={isEditMode}
      isViewMode={isViewMode}
      loading={loading}
    >
      <TransliteratedInput
        label="District Name"
        value={formData.district_name}
        onChange={(e) =>
          setFormData((prev) => ({
            ...prev,
            district_name: e.target.value,
          }))
        }
        valueMr={formData.district_name_mr}
        onChangeMr={(e) =>
          setFormData((prev) => ({
            ...prev,
            district_name_mr: e.target.value,
          }))
        }
        placeholder="Enter district name"
        placeholderMr="पुणे"
        required
        disabled={isViewMode}
      />
 
      <ToggleSwitch
  label="Active Status"
  description={formData.is_active ? 'District is currently active' : 'District is currently inactive'}
  checked={formData.is_active}
  onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
  disabled={isViewMode}
/>
    </FormLayout>
  );
};

export default DistrictForm;