import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { MapPin } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getTalukaById, createTaluka, updateTaluka, getDistricts } from '../../../services/master.service';
import toast from 'react-hot-toast';
import DropdownSearch from "../../../components/common/DropdownSearch";
import ToggleSwitch from '../../../components/common/ToggleSwitch';

const TalukaForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(true); // Start loading to fetch districts
    const [districts, setDistricts] = useState([]);

    const [formData, setFormData] = useState({
        taluka_name: '',
        taluka_name_mr: '',
        district_id: '',
        is_active: true
    });

    useEffect(() => {
        const loadData = async () => {
            setFetching(true);
            try {
                // 1. Fetch Districts for Dropdown
                // We fetch all districts roughly, currently spec supports pagination only?
                // For a dropdown, we usually want all active. 
                // Let's assume fetching with limit=100 or something if "all" isn't supported, 
                // but spec said "Support full list when called without page/limit".
                const districtRes = await getDistricts({ is_active: true });
                // If it returns array directly or inside object
                const districtList = Array.isArray(districtRes) ? districtRes : (districtRes.districts || []);
                setDistricts(districtList);

                // 2. If Edit or View Mode, Fetch Taluka
                if (isEditMode || isViewMode) {
                    const data = await getTalukaById(id);
                    setFormData({
                        taluka_name: data.taluka_name_en || data.taluka_name,
                        taluka_name_mr: data.taluka_name_mr || '',
                        district_id: data.district_id || '',
                        is_active: data.is_active
                    });
                }
            } catch (error) {
                console.error('Failed to load data', error);
                toast.error('Failed to load form data');
                if (isEditMode) navigate('/masters/talukas');
            } finally {
                setFetching(false);
            }
        };
        loadData();
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.taluka_name) {
            toast.error('Taluka Name is required');
            return;
        }
        if (!formData.district_id) {
            toast.error('District is required');
            return;
        }

        setLoading(true);
        try {
            if (isEditMode) {
                await updateTaluka(id, formData);
                toast.success('Taluka updated successfully');
            } else {
                await createTaluka(formData);
                toast.success('Taluka created successfully');
            }
            navigate('/masters/talukas');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save taluka');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <FormLayout
            title="Taluka"
            icon={MapPin}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/talukas')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            {/* District Dropdown */}
            <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">
                    District <span className="text-red-500">*</span>
                </label>
                <DropdownSearch
                    value={formData.district_id}
                    onChange={(e) => setFormData(prev => ({ ...prev, district_id: e.target.value }))}
                    options={districts.map(d => ({
                        id: d.district_id,
                        name: d.district_name,
                        name_mr: d.district_name_mr
                    }))}
                    placeholder="Select District"
                    icon={MapPin}
                    disabled={isViewMode}
                />
            </div>

            {/* Taluka Name */}
            <TransliteratedInput
                label="Taluka Name"
                value={formData.taluka_name}
                onChange={(e) => setFormData(prev => ({ ...prev, taluka_name: e.target.value }))}
                valueMr={formData.taluka_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, taluka_name_mr: e.target.value }))}
                placeholder="Enter taluka name"
                placeholderMr="बारामती"
                disabled={isViewMode}
                required
            />

            {/* Active Status Toggle */}
            <ToggleSwitch
                    label="Active Status"
                    description={formData.is_active ? 'Taluka is currently active' : 'Taluka is currently inactive'}
                    checked={formData.is_active}
                    onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                    disabled={isViewMode}
                    />
        </FormLayout>
    );
};

export default TalukaForm;