import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getDistricts, deleteDistrict } from '../../../services/master.service';
import toast from 'react-hot-toast';

const DistrictList = () => {
    const navigate = useNavigate();
    const [districts, setDistricts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    // Fetch Data
    const fetchDistricts = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getDistricts({
                page,
                limit,
                search: searchQuery,
                include_inactive: true // We generally want to see all in admin
            });

            // Expected response: { districts: [...], pagination: {...} }
            setDistricts(response.districts || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch districts', err);
            toast.error(err.message || 'Failed to load districts');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchDistricts();
    }, [fetchDistricts]);

    // Handlers
    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;

        try {
            // Determine if ID is in item (could be row object)
            const ids = items.map(item => item.district_id);

            await Promise.all(ids.map(id => deleteDistrict(id)));
            toast.success('District(s) deleted successfully');
            fetchDistricts();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete district');
        }
    };

    // Columns
    const columns = useMemo(
        () => [
            { key: 'district_name', header: 'Name (EN)', sortable: true },
            { key: 'district_name_mr', header: 'Name (MR)', sortable: true },
            {
                key: 'is_active',
                header: 'Status',
                render: (_, row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (_value, row, helpers) => (
                    <TableActions
                        onView={() => navigate(`/masters/districts/view/${row.district_id}`)}
                        onEdit={() => navigate(`/masters/districts/edit/${row.district_id}`)}
                        onDelete={() => helpers?.onDelete?.()}
                        viewPermission="masters.districts.view"
                        editPermission="masters.districts.edit"
                        deletePermission="masters.districts.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Districts"
                description="Manage districts master data"
                actionLabel="Add District"
                onAction={() => navigate('/masters/districts/add')}
                permission="masters.districts.create"
            />

            <DataTable
                columns={columns}
                data={districts}
                onSearch={setSearchQuery}
                showRowNumbers={true} // DataTable handles debounce
                onDelete={handleDelete}   // DataTable handles selection
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="district_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default DistrictList;
