import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getApplicationStatuses, deleteApplicationStatus } from '../../../services/master.service';
import toast from 'react-hot-toast';

const ApplicationStatusList = () => {
    const navigate = useNavigate();
    const [statuses, setStatuses] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);

    const fetchStatuses = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getApplicationStatuses({ page, limit, search: searchQuery, include_inactive: true });
            setStatuses(response.statuses || []);
            setTotalPages(response.pagination?.totalPages || 1);
        } catch (err) {
            console.error('Failed to fetch statuses', err);
            toast.error(err.message || 'Failed to load statuses');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchStatuses();
    }, [fetchStatuses]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;
        try {
            await Promise.all(items.map(item => deleteApplicationStatus(item.status_id)));
            toast.success('Status(es) deleted successfully');
            fetchStatuses();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete status');
        }
    };

    const columns = useMemo(() => [
        { key: 'status_code', header: 'Code', sortable: true },
        { key: 'status_name', header: 'Name (EN)', sortable: true },
        { key: 'display_order', header: 'Display Order', sortable: true },
        {
            key: 'is_active',
            header: 'Status',
            render: (row) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                    {row.is_active ? 'Active' : 'Inactive'}
                </span>
            )
        },
        {
            key: 'actions',
            header: 'Actions',
            render: (row) => (
                <TableActions
                    onView={() => navigate(`/masters/application-statuses/view/${row.status_id}`)}
                    onEdit={() => navigate(`/masters/application-statuses/edit/${row.status_id}`)}
                    onDelete={() => handleDelete([row])}
                    viewPermission="masters.application_statuses.view"
                    editPermission="masters.application_statuses.edit"
                    deletePermission="masters.application_statuses.delete"
                />
            ),
        },
    ], [navigate]);

    return (
        <div className="space-y-6">
            <PageHeader
                title="Application Statuses"
                description="Manage application statuses master data"
                actionLabel="Add Status"
                onAction={() => navigate('/masters/application-statuses/add')}
                permission="masters.application_statuses.create"
            />
            <DataTable
                columns={columns}
                data={statuses}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: setLimit,
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="status_id"
            />
        </div>
    );
};

export default ApplicationStatusList;
