import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getExperienceDomains, deleteExperienceDomain } from '../../../services/master.service';
import toast from 'react-hot-toast';

const ExperienceDomainList = () => {
    const navigate = useNavigate();
    const [experienceDomains, setExperienceDomains] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchExperienceDomains = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getExperienceDomains({
                page,
                limit,
                search: searchQuery,
                include_inactive: true
            });

            const domains = response?.domains || [];
            const pagination = response?.pagination || {};

            setExperienceDomains(domains);
            setTotalPages(pagination.totalPages || 1);
            setTotalItems(pagination.total ?? pagination.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch experience domains', err);
            toast.error(err.message || 'Failed to load experience domains');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchExperienceDomains();
    }, [fetchExperienceDomains]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;
        try {
            // Use domain_id for deletion
            await Promise.all(items.map(item => deleteExperienceDomain(item.domain_id)));
            toast.success('Experience domain(s) deleted successfully');
            fetchExperienceDomains();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete experience domain');
        }
    };

    const columns = useMemo(() => [
        { key: 'domain_code', header: 'Code', sortable: true },
        { key: 'domain_name', header: 'Name (EN)', sortable: true },
        { key: 'domain_name_mr', header: 'Name (MR)', sortable: true },
        // {
        //     key: 'doc_type_id',
        //     header: 'Document Type',
        //     render: (_, row) => (
        //         <span className="text-sm text-slate-600">
        //             {row?.doc_type?.doc_type_code}
        //         </span>
        //     )
        // },
        {
            key: 'is_active',
            header: 'Status',
            render: (_, row) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                    {row.is_active ? 'Active' : 'Inactive'}
                </span>
            )
        },
        {
            key: 'actions',
            header: 'Actions',
            render: (_, row, helpers) => (
                <TableActions
                    onView={() => navigate(`/masters/experience-domains/view/${row.domain_id}`)}
                    onEdit={() => navigate(`/masters/experience-domains/edit/${row.domain_id}`)}
                    onDelete={() => helpers?.onDelete?.()}
                    viewPermission={["masters.experience-domains.view", "masters.experience_domains.view"]}
                    editPermission={[
                        "masters.experience-domains.update",
                        "masters.experience-domains.edit",
                        "masters.experience_domains.update",
                        "masters.experience_domains.edit"
                    ]}
                    deletePermission={["masters.experience-domains.delete", "masters.experience_domains.delete"]}
                />
            ),
        },
    ], [navigate]);

    console.log('Component state:', {
        experienceDomains,
        loading,
        page,
        limit,
        totalPages,
        totalItems
    });

    return (
        <div className="space-y-6">
            <PageHeader
                title="Experience Domains"
                description="Manage experience domains master data"
                actionLabel="Add Experience Domain"
                onAction={() => navigate('/masters/experience-domains/add')}
                permission={["masters.experience-domains.create", "masters.experience_domains.create"]}
            />
            <DataTable
                columns={columns}
                data={experienceDomains}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newSize) => {
                        setLimit(newSize);
                        setPage(1); // Reset to first page when page size changes
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="domain_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default ExperienceDomainList;