import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getSchemeTypes, deleteSchemeType } from '../../../services/master.service';
import toast from 'react-hot-toast';

const SchemeTypeList = () => {
    const navigate = useNavigate();
    const [schemeTypes, setSchemeTypes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchSchemeTypes = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getSchemeTypes({
                page,
                limit,
                search: searchQuery,
                include_inactive: true
            });

            setSchemeTypes(response.schemeTypes || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch scheme types', err);
            toast.error(err.message || 'Failed to load scheme types');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchSchemeTypes();
    }, [fetchSchemeTypes]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;

        try {
            const ids = items.map(item => item.scheme_type_id);
            await Promise.all(ids.map(id => deleteSchemeType(id)));
            toast.success('Scheme type(s) deleted successfully');
            fetchSchemeTypes();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete scheme type');
        }
    };

    const columns = useMemo(
        () => [
            { key: 'scheme_code', header: 'Code', sortable: true },
            { key: 'scheme_name', header: 'Scheme Name', sortable: true },
            { key: 'description', header: 'Description', sortable: true },
            {
                key: 'is_active',
                header: 'Status',
                render: (_, row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (_value, row, helpers) => (
                    <TableActions
                        onView={() => navigate(`/masters/scheme-types/view/${row.scheme_type_id}`)}
                        onEdit={() => navigate(`/masters/scheme-types/edit/${row.scheme_type_id}`)}
                        onDelete={() => helpers?.onDelete?.()}
                        viewPermission="masters.scheme-types.view"
                        editPermission="masters.scheme-types.edit"
                        deletePermission="masters.scheme-types.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Scheme Types"
                description="Manage scheme types (OSC, Hub, 181, etc.)"
                actionLabel="Add Scheme Type"
                onAction={() => navigate('/masters/scheme-types/add')}
                permission="masters.scheme-types.create"
            />

            <DataTable
                columns={columns}
                data={schemeTypes}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="scheme_type_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default SchemeTypeList;
