import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { Input } from '../../../components/common/Input';
import { MediaViewer } from '../../../components/common/MediaViewer';
import { getBannerById, createBanner, updateBanner } from '../../../services/master.service';
import { PUBLIC_FILE_BASE_URL } from '../../../config/appConfig';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { Image, Upload } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';

const BannerForm = ({ isViewMode = false }) => {
  const navigate = useNavigate();
  const { id } = useParams();

  const isEdit = Boolean(id) && !isViewMode;
  const isView = Boolean(id) && isViewMode;

  const [form, setForm] = useState({
    display_order: 0,
    is_active: true,
    banner_image: null,
    banner_image_mr: null
  });
  const [existing, setExisting] = useState(null);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(isEdit || isView);
  const [imagePreview, setImagePreview] = useState(null);
  const [imagePreviewMr, setImagePreviewMr] = useState(null);

  const buildImageUrl = useMemo(
    () => (path) => {
      if (!path) return null;
      // If backend already returns absolute URL, use it directly
      if (/^https?:\/\//i.test(path)) return path;
      const normalizedPath = path.startsWith('/') ? path.slice(1) : path;
      return `${PUBLIC_FILE_BASE_URL}/${normalizedPath}`;
    },
    []
  );

  useEffect(() => {
    const load = async () => {
      if (!id) return;
      setFetching(true);
      try {
        const data = await getBannerById(id);
        setExisting(data);
        setForm({
          display_order: data.display_order ?? 0,
          is_active: data.is_active ?? true,
          banner_image: null,
          banner_image_mr: null
        });
      } catch (error) {
        console.error('Failed to load banner', error);
        toast.error(error.message || 'Failed to load banner');
        navigate('/masters/banners');
      } finally {
        setFetching(false);
      }
    };
    load();
  }, [id, isEdit, isView, navigate]);

  const onChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const onFileChange = (e, fieldName) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.match(/^image\/(jpeg|png)$/)) {
        toast.error('Only JPEG and PNG images are allowed');
        return;
      }
      if (file.size > 2 * 1024 * 1024) {
        toast.error('Image size must be less than 2MB');
        return;
      }
      onChange(fieldName, file);
      const reader = new FileReader();
      reader.onloadend = () => {
        if (fieldName === 'banner_image') {
          setImagePreview(reader.result);
        } else {
          setImagePreviewMr(reader.result);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    if (!isEdit && !form.banner_image) {
      toast.error('Banner image is required');
      return;
    }

    try {
      setLoading(true);
      if (isEdit) {
        await updateBanner(id, form);
        toast.success('Banner updated successfully');
      } else {
        await createBanner(form);
        toast.success('Banner created successfully');
      }
      navigate('/masters/banners');
    } catch (error) {
      console.error('Save failed', error);
      toast.error(error.message || 'Failed to save banner');
    } finally {
      setLoading(false);
    }
  };

  if (fetching) {
    return <div className="p-8 text-center text-slate-500">Loading...</div>;
  }

  return (
    <FormLayout
      title="Banner"
      icon={Image}
      onSubmit={onSubmit}
      onCancel={() => navigate('/masters/banners')}
      isEditMode={isEdit}
      isViewMode={isView}
      loading={loading}
    >
      <Input
        label="Display Order"
        type="number"
        value={form.display_order}
        onChange={(e) => onChange('display_order', Number(e.target.value))}
        placeholder="Enter display order (0 for first)"
        disabled={isView}
      />

      {/* Active Status Toggle */}
        <ToggleSwitch
        label="Active Status"
        description={form.is_active ? 'Banner is currently active' : 'Banner is currently inactive'}
        checked={form.is_active}
        onChange={(val) => onChange('is_active', val)}
        disabled={isView}
      />
      {/* English Banner Image */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-slate-700">
          Banner Image (English) {!isEdit && <span className="text-red-500">*</span>}
        </label>
        <p className="text-xs text-slate-500">Upload banner image for English (JPEG/PNG, max 2MB)</p>

        {!isView && (
          <div className="flex items-center gap-4">
            <label className="cursor-pointer">
              <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors">
                <Upload className="h-4 w-4" />
                <span className="text-sm font-medium">Choose Image</span>
              </div>
              <input
                type="file"
                accept="image/jpeg,image/png"
                onChange={(e) => onFileChange(e, 'banner_image')}
                className="hidden"
              />
            </label>
            {form.banner_image && (
              <span className="text-sm text-slate-600">{form.banner_image.name}</span>
            )}
          </div>
        )}

              {/* Image Preview */}
        {(imagePreview || existing?.banner_image_path) && (
          <div className="mt-4">
            <p className="text-sm font-medium text-slate-700 mb-2">
              {imagePreview ? 'New Image Preview' : 'Current Image'}
            </p>
            <div className="border border-slate-200 rounded-lg p-4 bg-slate-50">
              {imagePreview ? (
                      <img
                        src={imagePreview}
                        alt="Banner preview"
                        className="max-w-full h-auto rounded"
                      />
              ) : (
                <img
                  src={buildImageUrl(existing.banner_image_path)}
                  alt="Current banner"
                  className="max-w-full h-auto rounded cursor-pointer"
                  onClick={(e) => {
                    e.preventDefault();
                    const url = buildImageUrl(existing.banner_image_path);
                    if (url) window.open(url, '_blank');
                  }}
                />
              )}
            </div>
          </div>
        )}
      </div>

      {/* Marathi Banner Image */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-slate-700">
          Banner Image (Marathi) <span className="text-slate-500 text-xs">(Optional)</span>
        </label>
        <p className="text-xs text-slate-500">Upload banner image for Marathi (JPEG/PNG, max 2MB)</p>

        {!isView && (
          <div className="flex items-center gap-4">
            <label className="cursor-pointer">
              <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors">
                <Upload className="h-4 w-4" />
                <span className="text-sm font-medium">Choose Image</span>
              </div>
              <input
                type="file"
                accept="image/jpeg,image/png"
                onChange={(e) => onFileChange(e, 'banner_image_mr')}
                className="hidden"
              />
            </label>
            {form.banner_image_mr && (
              <span className="text-sm text-slate-600">{form.banner_image_mr.name}</span>
            )}
          </div>
        )}

              {/* Image Preview */}
        {(imagePreviewMr || existing?.banner_image_path_mr) && (
          <div className="mt-4">
            <p className="text-sm font-medium text-slate-700 mb-2">
              {imagePreviewMr ? 'New Image Preview' : 'Current Image'}
            </p>
            <div className="border border-slate-200 rounded-lg p-4 bg-slate-50">
              {imagePreviewMr ? (
                      <img
                        src={imagePreviewMr}
                        alt="Banner preview (Marathi)"
                        className="max-w-full h-auto rounded"
                      />
              ) : (
                <img
                  src={buildImageUrl(existing.banner_image_path_mr)}
                  alt="Current banner (Marathi)"
                  className="max-w-full h-auto rounded cursor-pointer"
                  onClick={(e) => {
                    e.preventDefault();
                    const url = buildImageUrl(existing.banner_image_path_mr);
                    if (url) window.open(url, '_blank');
                  }}
                />
              )}
            </div>
          </div>
        )}
      </div>
    </FormLayout>
  );
};

export default BannerForm;