import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getEducationLevels, deleteEducationLevel } from '../../../services/master.service';
import toast from 'react-hot-toast';

const EducationLevelList = () => {
    const navigate = useNavigate();
    const [levels, setLevels] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchLevels = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getEducationLevels({ page, limit, search: searchQuery, include_inactive: true });
            setLevels(response.educationLevels || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch education levels', err);
            toast.error(err.message || 'Failed to load education levels');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchLevels();
    }, [fetchLevels]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;
        try {
            await Promise.all(items.map(item => deleteEducationLevel(item.level_id)));
            toast.success('Education level(s) deleted successfully');
            fetchLevels();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete education level');
        }
    };

    const columns = useMemo(() => [
        { key: 'level_code', header: 'Code', sortable: true },
        { key: 'level_name', header: 'Name (EN)', sortable: true },
        // {
        //     key: 'doc_type_id',
        //     header: 'Document Type',
        //     render: (_, row) => (
        //         <span className="text-sm text-slate-600">
        //             {row?.doc_type?.doc_type_code}
        //         </span>
        //     )
        // },
        { key: 'display_order', header: 'Display Order', sortable: true },
        {
            key: 'is_active',
            header: 'Status',
            render: (_, row) => (
                <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                    {row.is_active ? 'Active' : 'Inactive'}
                </span>
            )
        },
        {
            key: 'actions',
            header: 'Actions',
            render: (_value, row, helpers) => (
                <TableActions
                    onView={() => navigate(`/masters/education-levels/view/${row.level_id}`)}
                    onEdit={() => navigate(`/masters/education-levels/edit/${row.level_id}`)}
                    onDelete={() => helpers?.onDelete?.()}
                    viewPermission="masters.education_levels.view"
                    editPermission="masters.education_levels.edit"
                    deletePermission="masters.education_levels.delete"
                />
            ),
        },
    ], [navigate]);

    return (
        <div className="space-y-6">
            <PageHeader
                title="Education Levels"
                description="Manage education levels master data"
                actionLabel="Add Education Level"
                onAction={() => navigate('/masters/education-levels/add')}
                permission="masters.education_levels.create"
            />
            <DataTable columns={columns} data={levels} onSearch={setSearchQuery} onDelete={handleDelete} pagination={{ currentPage: page, totalPages, totalItems, onPageChange: setPage, pageSize: limit, onPageSizeChange: (l) => { setLimit(l); setPage(1); }, pageSizeOptions: [10, 25, 50, 100] }} isLoading={loading} rowKey="level_id" headerClassName="bg-slate-900 text-white" showRowNumbers={true} />
        </div>
    );
};

export default EducationLevelList;
