import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { Button } from '../../../components/common/Button';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getCategories, deleteCategory } from '../../../services/master.service';
import toast from 'react-hot-toast';

const CategoryList = () => {
    const navigate = useNavigate();
    const [categories, setCategories] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);

    // Fetch Data
    const fetchCategories = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getCategories({
                page,
                limit,
                search: searchQuery,
                include_inactive: true
            });

            // Match the structure from your JSON - response should have "categories" array
            setCategories(response.categories || []);
            setTotalPages(response.pagination?.totalPages || 1);
        } catch (error) {
            console.error('Failed to fetch categories', error);
            toast.error(error.message || 'Failed to load categories');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchCategories();
    }, [fetchCategories]);

    // Handlers
    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;

        try {
            const ids = items.map(item => item.category_id);
            await Promise.all(ids.map(id => deleteCategory(id)));
            toast.success('Category(s) deleted successfully');
            fetchCategories();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete category');
        }
    };

    // Columns
    const columns = useMemo(
        () => [
            {
                key: 'category_code',
                header: 'Code',
                sortable: true
            },
            {
                key: 'category_name_en', // Use the actual field from JSON
                header: 'Name (EN)',
                sortable: true
            },
            {
                key: 'category_name_mr',
                header: 'Name (MR)',
                sortable: true
            },
            // {
            //     key: 'display_order',
            //     header: 'Order',
            //     sortable: true
            // },
            {
                key: 'is_active',
                header: 'Status',
                render: (row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (row) => (
                    <TableActions
                        onView={() => navigate(`/masters/categories/view/${row.category_id}`)}
                        onEdit={() => navigate(`/masters/categories/edit/${row.category_id}`)}
                        onDelete={() => handleDelete([row])}
                        viewPermission="masters.categories.view"
                        editPermission="masters.categories.edit"
                        deletePermission="masters.categories.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Categories"
                description="Manage category master data"
                actionLabel="Add Category"
                onAction={() => navigate('/masters/categories/add')}
                permission="masters.categories.create"
            />

            <DataTable
                columns={columns}
                data={categories}
                onSearch={setSearchQuery} 
                showRowNumbers={true} 
                onDelete={handleDelete}   
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="category_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default CategoryList;