import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import DistrictList from '../pages/masters/districts/DistrictList';
import DistrictForm from '../pages/masters/districts/DistrictForm';
import TalukaList from '../pages/masters/talukas/TalukaList';
import TalukaForm from '../pages/masters/talukas/TalukaForm';
import SchemeList from '../pages/masters/schemes/SchemeList';
import SchemeForm from '../pages/masters/schemes/SchemeForm';
import SchemeTypeList from '../pages/masters/scheme-types/SchemeTypeList';
import SchemeTypeForm from '../pages/masters/scheme-types/SchemeTypeForm';
import DepartmentList from '../pages/masters/departments/DepartmentList';
import DepartmentForm from '../pages/masters/departments/DepartmentForm';
import PostList from '../pages/masters/posts/PostList';
import PostForm from '../pages/masters/posts/PostForm';
import DocumentTypeList from '../pages/masters/document-types/DocumentTypeList';
import DocumentTypeForm from '../pages/masters/document-types/DocumentTypeForm';
import ApplicationStatusList from '../pages/masters/application-statuses/ApplicationStatusList';
import ApplicationStatusForm from '../pages/masters/application-statuses/ApplicationStatusForm';
import EducationLevelList from '../pages/masters/education-levels/EducationLevelList';
import EducationLevelForm from '../pages/masters/education-levels/EducationLevelForm';

import CategoryList from '../pages/masters/categories/CategoryList';
import CategoryForm from '../pages/masters/categories/CategoryForm';

import ExperienceDomainList from '../pages/masters/experience-domains/ExperienceDomainList';
import ExperienceDomainForm from '../pages/masters/experience-domains/ExperienceDomainForm';

import SkillList from '../pages/masters/skills/SkillList';
import SkillForm from '../pages/masters/skills/SkillForm';
import BannerList from '../pages/masters/banners/BannerList';
import BannerForm from '../pages/masters/banners/BannerForm';

const MasterRoutes = () => {
    return (
        <Routes>
            <Route path="/" element={<Navigate to="districts" replace />} />

            {/* Districts */}
            <Route path="districts" element={<DistrictList />} />
            <Route path="districts/add" element={<DistrictForm />} />
            <Route path="districts/edit/:id" element={<DistrictForm />} />
            <Route path="districts/view/:id" element={<DistrictForm isViewMode />} />

            {/* Talukas */}
            <Route path="talukas" element={<TalukaList />} />
            <Route path="talukas/add" element={<TalukaForm />} />
            <Route path="talukas/edit/:id" element={<TalukaForm />} />
            <Route path="talukas/view/:id" element={<TalukaForm isViewMode />} />

            {/* Schemes */}
            <Route path="schemes" element={<SchemeList />} />
            <Route path="schemes/add" element={<SchemeForm />} />
            <Route path="schemes/edit/:id" element={<SchemeForm />} />
            <Route path="schemes/view/:id" element={<SchemeForm isViewMode />} />

            {/* Scheme Types */}
            <Route path="scheme-types" element={<SchemeTypeList />} />
            <Route path="scheme-types/add" element={<SchemeTypeForm />} />
            <Route path="scheme-types/edit/:id" element={<SchemeTypeForm />} />
            <Route path="scheme-types/view/:id" element={<SchemeTypeForm isViewMode />} />

            {/* Departments */}
            <Route path="departments" element={<DepartmentList />} />
            <Route path="departments/add" element={<DepartmentForm />} />
            <Route path="departments/edit/:id" element={<DepartmentForm />} />
            <Route path="departments/view/:id" element={<DepartmentForm isViewMode />} />

            {/* Posts */}
            <Route path="posts" element={<PostList />} />
            <Route path="posts/add" element={<PostForm />} />
            <Route path="posts/edit/:id" element={<PostForm />} />
            <Route path="posts/view/:id" element={<PostForm isViewMode />} />

            {/* Document Types */}
            <Route path="document-types" element={<DocumentTypeList />} />
            <Route path="document-types/add" element={<DocumentTypeForm />} />
            <Route path="document-types/edit/:id" element={<DocumentTypeForm />} />
            <Route path="document-types/view/:id" element={<DocumentTypeForm isViewMode />} />

            {/* Application Statuses */}
            <Route path="application-statuses" element={<ApplicationStatusList />} />
            <Route path="application-statuses/add" element={<ApplicationStatusForm />} />
            <Route path="application-statuses/edit/:id" element={<ApplicationStatusForm />} />
            <Route path="application-statuses/view/:id" element={<ApplicationStatusForm isViewMode />} />

            {/* Education Levels */}
            <Route path="education-levels" element={<EducationLevelList />} />
            <Route path="education-levels/add" element={<EducationLevelForm />} />
            <Route path="education-levels/edit/:id" element={<EducationLevelForm />} />
            <Route path="education-levels/view/:id" element={<EducationLevelForm isViewMode />} />

            {/* Categories */}
            <Route path="categories" element={<CategoryList />} />
            <Route path="categories/add" element={<CategoryForm />} />
            <Route path="categories/edit/:id" element={<CategoryForm />} />
            <Route path="categories/view/:id" element={<CategoryForm isViewMode />} />

            {/* Experience Domains */}
            <Route path="experience-domains" element={<ExperienceDomainList />} />
            <Route path="experience-domains/add" element={<ExperienceDomainForm />} />
            <Route path="experience-domains/edit/:id" element={<ExperienceDomainForm />} />
            <Route path="experience-domains/view/:id" element={<ExperienceDomainForm isViewMode />} />

            {/* Skills */}
            <Route path="skills" element={<SkillList />} />
            <Route path="skills/add" element={<SkillForm />} />
            <Route path="skills/edit/:id" element={<SkillForm />} />
            <Route path="skills/view/:id" element={<SkillForm isViewMode />} />

            {/* Banners */}
            <Route path="banners" element={<BannerList />} />
            <Route path="banners/add" element={<BannerForm />} />
            <Route path="banners/edit/:id" element={<BannerForm />} />
            <Route path="banners/view/:id" element={<BannerForm isViewMode />} />

            {/* Scheme Types */}
            <Route path="scheme-types" element={<SchemeTypeList />} />
            <Route path="scheme-types/add" element={<SchemeTypeForm />} />
            <Route path="scheme-types/edit/:id" element={<SchemeTypeForm />} />
            <Route path="scheme-types/view/:id" element={<SchemeTypeForm isViewMode />} />
        </Routes>
    );
};

export default MasterRoutes;
