import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Lightbulb } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getSkillById, createSkill, updateSkill } from '../../../services/master.service';
import toast from 'react-hot-toast';
import ToggleSwitch from '../../../components/common/ToggleSwitch';

const SkillForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);

    const [formData, setFormData] = useState({
        skill_name: '',
        skill_name_mr: '',
        description: '',
        description_mr: '',
        is_active: true
    });

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchSkill = async () => {
                setFetching(true);
                try {
                    const data = await getSkillById(id);
                    setFormData({
                        skill_name: data.skill_name_en || data.skill_name || '',
                        skill_name_mr: data.skill_name_mr || '',
                        description: data.description_en || data.description || '',
                        description_mr: data.description_mr || '',
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch skill', error);
                    toast.error('Failed to load skill details');
                    navigate('/masters/skills');
                } finally {
                    setFetching(false);
                }
            };
            fetchSkill();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.skill_name) {
            toast.error('Skill Name is required');
            return;
        }

        setLoading(true);
        try {
            if (isEditMode) {
                await updateSkill(id, formData);
                toast.success('Skill updated successfully');
            } else {
                await createSkill(formData);
                toast.success('Skill created successfully');
            }
            navigate('/masters/skills');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save skill');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <FormLayout
            title="Skill"
            icon={Lightbulb}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/skills')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <TransliteratedInput
                label="Skill Name"
                value={formData.skill_name}
                onChange={(e) => setFormData(prev => ({ ...prev, skill_name: e.target.value }))}
                valueMr={formData.skill_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, skill_name_mr: e.target.value }))}
                placeholder="Enter skill name"
                placeholderMr="कौशल्य"
                disabled={isViewMode}
                required
            />

            {/* Description */}
            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Describe the skill..."
                placeholderMr="कौशल्याचे वर्णन..."
                isTextArea
                disabled={isViewMode}
            />

            {/* Active Status Toggle */}
            <ToggleSwitch
                label="Active Status"
                description={formData.is_active ? 'Skill is currently active' : 'Skill is currently inactive'}
                checked={formData.is_active}
                onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                disabled={isViewMode}
                />
        </FormLayout>
    );
};

export default SkillForm;