import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft, Save } from 'lucide-react';
import { Button } from '../../../components/common/Button';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getCategoryById, createCategory, updateCategory } from '../../../services/master.service';
import toast from 'react-hot-toast';

const CategoryForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;

    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(false);

    const [formData, setFormData] = useState({
        category_code: '',
        category_name: '',
        category_name_mr: '',
        description: '',
        description_mr: '',
        display_order: 0,
        is_active: true
    });

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const loadData = async () => {
                setFetching(true);
                try {
                    const data = await getCategoryById(id);
                    setFormData({
                        category_code: data.category_code || '',
                        category_name: data.category_name || '',
                        category_name_mr: data.category_name_mr || '',
                        description: data.description || '',
                        description_mr: data.description_mr || '',
                        display_order: data.display_order || 0,
                        is_active: data.is_active !== undefined ? data.is_active : true
                    });
                } catch (error) {
                    console.error('Failed to load category', error);
                    toast.error('Failed to load category details');
                    navigate('/masters/categories');
                } finally {
                    setFetching(false);
                }
            };
            loadData();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!formData.category_code || !formData.category_name) {
            toast.error('Please fill in required fields');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            // if (payload.display_order) payload.display_order = Number(payload.display_order);

            if (isEditMode) {
                await updateCategory(id, payload);
                toast.success('Category updated successfully');
            } else {
                await createCategory(payload);
                toast.success('Category created successfully');
            }
            navigate('/masters/categories');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save category');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) {
        return <div className="p-8 text-center text-slate-500">Loading...</div>;
    }

    return (
        <div className="max-w-2xl mx-auto space-y-6">
            <div className="flex items-center gap-4">
                <Button
                    variant="ghost"
                    onClick={() => navigate('/masters/categories')}
                    leftIcon={<ArrowLeft className="h-4 w-4 mr-2" />}
                />
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">
                        {isViewMode ? 'View Category' : isEditMode ? 'Edit Category' : 'Add New Category'}
                    </h1>
                </div>
            </div>

            <div className="bg-white rounded-lg shadow border border-slate-200 p-6">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <Input
                            label="Category Code "
                            value={formData.category_code}
                            onChange={(e) => setFormData(prev => ({ ...prev, category_code: e.target.value }))}
                            placeholder="e.g. GEN, OBC"
                            required
                            disabled={isViewMode || isEditMode}
                        />

                        {/* <Input
                            label="Display Order"
                            type="number"
                            value={formData.display_order}
                            onChange={(e) => setFormData(prev => ({ ...prev, display_order: e.target.value }))}
                            disabled={isViewMode}
                        /> */}

                        <TransliteratedInput
                            label="Category Name"
                            value={formData.category_name}
                            onChange={(e) => setFormData(prev => ({ ...prev, category_name: e.target.value }))}
                            valueMr={formData.category_name_mr}
                            onChangeMr={(e) => setFormData(prev => ({ ...prev, category_name_mr: e.target.value }))}
                            placeholder="General"
                            placeholderMr="सामान्य"
                            disabled={isViewMode}
                            required
                        />
                    </div>

                    <div className="grid grid-cols-1 gap-6">
                        <TransliteratedInput
                            label="Description"
                            value={formData.description}
                            onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                            valueMr={formData.description_mr}
                            onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                            placeholder="Enter description..."
                            placeholderMr="मराठी वर्णन"
                            isTextArea
                            disabled={isViewMode}
                        />
                    </div>

                    <div className="flex items-center gap-2">
                        <input
                            type="checkbox"
                            id="is_active"
                            checked={formData.is_active}
                            onChange={(e) => setFormData(prev => ({ ...prev, is_active: e.target.checked }))}
                            className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4"
                            disabled={isViewMode}
                        />
                        <label htmlFor="is_active" className="text-sm font-medium text-slate-700">
                            Active Status
                        </label>
                    </div>

                    {!isViewMode && (
                        <div className="flex items-center justify-end gap-4 pt-4 border-t border-slate-200">
                            <Button
                                type="button"
                                variant="outline"
                                onClick={() => navigate('/masters/categories')}
                            >
                                Cancel
                            </Button>
                            <Button
                                type="submit"
                                isLoading={loading}
                                leftIcon={<Save className="h-4 w-4" />}
                            >
                                {isEditMode ? 'Update' : 'Create'}
                            </Button>
                        </div>
                    )}
                </form>
            </div>
        </div>
    );
};

export default CategoryForm;
