import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getDocumentTypeById, createDocumentType, updateDocumentType } from '../../../services/master.service';
import toast from 'react-hot-toast';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { FileText } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';

const DocumentTypeForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;
    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);

    const [formData, setFormData] = useState({
        doc_type_code: '',
        doc_type_name: '',
        doc_type_name_mr: '',
        description: '',
        description_mr: '',
        is_mandatory: false,
        allowed_formats: '',
        max_size_mb: '',
        is_active: true
    });

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchDocumentType = async () => {
                setFetching(true);
                try {
                    const data = await getDocumentTypeById(id);
                    setFormData({
                        doc_type_code: data.doc_type_code || '',
                        doc_type_name: data.doc_type_name_en || data.doc_type_name || '',
                        doc_type_name_mr: data.doc_type_name_mr || '',
                        description: data.description_en || data.description || '',
                        description_mr: data.description_mr || '',
                        is_mandatory: data.is_mandatory || false,
                        allowed_formats: data.allowed_formats || '',
                        max_size_mb: data.max_size_mb || '',
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch document type', error);
                    toast.error('Failed to load document type details');
                    navigate('/masters/document-types');
                } finally {
                    setFetching(false);
                }
            };
            fetchDocumentType();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.doc_type_code || !formData.doc_type_name) {
            toast.error('Code and Name are required');
            return;
        }
        if (formData.max_size_mb && isNaN(formData.max_size_mb)) {
            toast.error('Max Size must be a number');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            if (payload.max_size_mb) {
                payload.max_size_mb = Number(payload.max_size_mb);
                if (payload.max_size_mb < 0) {
                    toast.error('Max Size cannot be negative');
                    setLoading(false);
                    return;
                }
            } else {
                delete payload.max_size_mb; 
            }

            if (isEditMode) {
                await updateDocumentType(id, payload);
                toast.success('Document type updated successfully');
            } else {
                await createDocumentType(payload);
                toast.success('Document type created successfully');
            }
            navigate('/masters/document-types');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save document type');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) return <div className="p-8 text-center text-slate-500">Loading...</div>;

    return (
        <FormLayout
            title="Document Type"
            icon={FileText}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/document-types')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <Input
                label="Document Type Code"
                value={formData.doc_type_code}
                onChange={(e) => setFormData(prev => ({ ...prev, doc_type_code: e.target.value }))}
                placeholder="AADHAR"
                required
                disabled={isViewMode || isEditMode}
            />
            <TransliteratedInput
                label="Document Type Name"
                value={formData.doc_type_name}
                onChange={(e) => setFormData(prev => ({ ...prev, doc_type_name: e.target.value }))}
                valueMr={formData.doc_type_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, doc_type_name_mr: e.target.value }))}
                placeholder="Aadhaar Card"
                placeholderMr="आधार कार्ड"
                disabled={isViewMode}
                required
            />
                        {/* <Input label="Allowed Formats" value={formData.allowed_formats} onChange={(e) => setFormData(prev => ({ ...prev, allowed_formats: e.target.value }))} placeholder="pdf,jpg,jpeg,png" disabled={isViewMode} /> */}
                        {/* <Input label="Max Size (MB)" type="number" value={formData.max_size_mb} onChange={(e) => setFormData(prev => ({ ...prev, max_size_mb: e.target.value }))} placeholder="2" min="0" disabled={isViewMode} /> */}
            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Enter description..."
                placeholderMr="मराठी वर्णन"
                isTextArea
                disabled={isViewMode}
            />

            {/* Mandatory Toggle */}
            <div className="flex items-center justify-between rounded-xl border border-slate-200 bg-slate-50 px-4 py-3">
                <div>
                    <p className="text-sm font-semibold text-slate-700">Mandatory</p>
                    <p className="text-xs text-slate-400 mt-0.5">
                        {formData.is_mandatory ? 'Document is mandatory' : 'Document is optional'}
                    </p>
                </div>
                <button
                    type="button"
                    disabled={isViewMode}
                    onClick={() => setFormData(prev => ({ ...prev, is_mandatory: !prev.is_mandatory }))}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors duration-200
                        ${formData.is_mandatory ? 'bg-blue-500' : 'bg-slate-300'}
                        ${isViewMode ? 'opacity-60 cursor-not-allowed' : 'cursor-pointer'}`}
                >
                    <span className={`inline-block h-4 w-4 transform rounded-full bg-white shadow transition-transform duration-200
                        ${formData.is_mandatory ? 'translate-x-6' : 'translate-x-1'}`}
                    />
                </button>
            </div>
            {/* Active Status Toggle */}
            <ToggleSwitch
                label="Active Status"
                    description={formData.is_active ? 'Document type is currently active' : 'Document type is currently inactive'}
                checked={formData.is_active}
                    onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                disabled={isViewMode}
            />
        </FormLayout>
    );
};

export default DocumentTypeForm;