import React, { useState, useEffect, useMemo, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { DataTable } from "../../../components/ui/DataTable";
import { Button } from "../../../components/common/Button";
import { PageHeader } from "../../../components/common/PageHeader";
import { TableActions } from "../../../components/common/TableActions";
import { getTalukas, deleteTaluka } from "../../../services/master.service";
import toast from "react-hot-toast";

const TalukaList = () => {
  const navigate = useNavigate();
  const [talukas, setTalukas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  // Fetch Data
  const fetchTalukas = useCallback(async () => {
    setLoading(true);
    try {
      const response = await getTalukas({
        page,
        limit,
        search: searchQuery,
        include_inactive: true,
      });

      setTalukas(response.talukas || []);
      setTotalPages(response.pagination?.totalPages || 1);
      setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
    } catch (err) {
      console.error("Failed to fetch talukas", err);
      toast.error(err.message || "Failed to load talukas");
    } finally {
      setLoading(false);
    }
  }, [page, limit, searchQuery]);

  useEffect(() => {
    fetchTalukas();
  }, [fetchTalukas]);

  // Handlers
  const handleDelete = async (items) => {
    if (!items || items.length === 0) return;

    try {
      const ids = items.map((item) => item.taluka_id);
      await Promise.all(ids.map((id) => deleteTaluka(id)));
      toast.success("Taluka(s) deleted successfully");
      fetchTalukas();
    } catch (error) {
      console.error("Delete failed", error);
      toast.error(error.message || "Failed to delete taluka");
    }
  };

  // Columns
  const columns = useMemo(
    () => [
      { key: "taluka_name", header: "Name (EN)", sortable: true },
      { key: "taluka_name_mr", header: "Name (MR)", sortable: true },
      {
        key: "district_name",
        header: "District",
        sortable: true,
        render: (_, row) =>
          row.district?.district_name || row.district_name || "-",
      },
      {
        key: "is_active",
        header: "Status",
        render: (_, row) => (
          <span
            className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active
              ? "bg-green-50 text-green-700"
              : "bg-red-50 text-red-700"
              }`}
          >
            {row.is_active ? "Active" : "Inactive"}
          </span>
        ),
      },
      {
        key: "actions",
        header: "Actions",
        render: (_value, row, helpers) => (
          <TableActions
            onView={() => navigate(`/masters/talukas/view/${row.taluka_id}`)}
            onEdit={() => navigate(`/masters/talukas/edit/${row.taluka_id}`)}
            onDelete={() => helpers?.onDelete?.()}
            viewPermission="masters.talukas.view"
            editPermission="masters.talukas.edit"
            deletePermission="masters.talukas.delete"
          />
        ),
      },
    ],
    [navigate]
  );

  return (
    <div className="space-y-6">
      <PageHeader
        title="Talukas"
        description="Manage talukas master data"
        actionLabel="Add Taluka"
        onAction={() => navigate("/masters/talukas/add")}
        permission="masters.talukas.create"
      />

      <DataTable
        columns={columns}
        data={talukas}
        onSearch={setSearchQuery}
        showRowNumbers={true}
        onDelete={handleDelete}
        deletePermission="masters.talukas.delete"
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50, 100],
        }}
        isLoading={loading}
        rowKey="taluka_id"
        headerClassName="bg-slate-900 text-white"
      />
    </div>
  );
};

export default TalukaList;
