import React, { useState, useEffect, useMemo, useCallback } from "react";
import { Edit2, Trash2, Eye, CheckSquare, X, RotateCcw } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { DataTable } from "../../../components/ui/DataTable";
import { PageHeader } from "../../../components/common/PageHeader";
import { Button } from "../../../components/common/Button";
import { TableActions } from "../../../components/common/TableActions";
import DropdownSearch from "../../../components/common/DropdownSearch";
import {
  getPosts,
  deletePost,
  closePost,
  reopenPost,
  bulkUpdatePosts,
  getEducationLevels,
  getDistricts /* , getCategories */,
} from "../../../services/master.service";
import toast from "react-hot-toast";

const PostList = () => {
  const navigate = useNavigate();
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [page, setPage] = useState(1);
  const [limit, setLimit] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);
  const [districts, setDistricts] = useState([]);
  const [selectedDistrict, setSelectedDistrict] = useState("");

  // Bulk Update State
  const [selectedPosts, setSelectedPosts] = useState([]);
  const [showBulkUpdate, setShowBulkUpdate] = useState(false);
  const [bulkData, setBulkData] = useState({
    min_education_level_id: "",
    max_education_level_id: "",
    // allowed_category_ids: []
  });
  const [educationLevels, setEducationLevels] = useState([]);
  // const [categories, setCategories] = useState([]);
  const [bulkUpdating, setBulkUpdating] = useState(false);
  // const [rowToDelete, setRowToDelete] = useState(null); // no longer needed with centralized delete

  const fetchPosts = useCallback(async () => {
    setLoading(true);
    try {
      const response = await getPosts({
        page,
        limit,
        search: searchQuery,
        include_inactive: true,
        district_id: selectedDistrict || undefined,
      });

      setPosts(response.posts || []);
      setTotalPages(response.pagination?.totalPages || 1);
      setTotalItems(
        response.pagination?.total ?? response.pagination?.totalItems ?? 0,
      );
    } catch (err) {
      console.error("Failed to fetch posts", err);
      toast.error(err.message || "Failed to load posts");
    } finally {
      setLoading(false);
    }
  }, [page, limit, searchQuery, selectedDistrict]);

  useEffect(() => {
    fetchPosts();
    loadBulkOptions();
    loadDistricts();
  }, [fetchPosts]);

  const loadBulkOptions = async () => {
    try {
      const eduRes = await getEducationLevels({ is_active: true });
      // Category APIs are disabled; skip fetching until they are restored
      setEducationLevels(
        Array.isArray(eduRes) ? eduRes : eduRes.educationLevels || [],
      );
    } catch (err) {
      console.error("Failed to load bulk options", err);
    }
  };

  const loadDistricts = async () => {
    try {
      const res = await getDistricts({ is_active: true });
      setDistricts(Array.isArray(res) ? res : res.districts || []);
    } catch (err) {
      console.error("Failed to load districts", err);
    }
  };

  const executeDelete = async (items) => {
    if (!items || items.length === 0) return;

    try {
      const ids = items.map((item) => item.post_id);
      await Promise.all(ids.map((id) => deletePost(id)));
      
      toast.success("Post(s) deleted successfully");
      fetchPosts();
      setSelectedPosts([]);
    } catch (error) {
      console.error("Delete failed", error);
      toast.error(error.message || "Failed to delete post");
    }
  };

  const handleBulkUpdate = async () => {
    if (!bulkData.min_education_level_id && !bulkData.max_education_level_id) {
      toast.error("Please select at least one field to update");
      return;
    }

    setBulkUpdating(true);
    try {
      const payload = {
        post_ids: selectedPosts.map((p) => p.post_id),
        updates: {},
      };

      if (bulkData.min_education_level_id)
        payload.updates.min_education_level_id =
          bulkData.min_education_level_id;
      if (bulkData.max_education_level_id)
        payload.updates.max_education_level_id =
          bulkData.max_education_level_id;
      // Category updates disabled while API is offline


      await bulkUpdatePosts(payload);
      toast.success("Batch update successful");
      setShowBulkUpdate(false);
      setBulkData({
        min_education_level_id: "",
        max_education_level_id: "" /* , allowed_category_ids: [] */,
      });
      setSelectedPosts([]); // Optional: Clear selection after update? User might want to do more... let's keep it or clear it? Standard is usually clear.
      fetchPosts();
    } catch (error) {
      console.error("Bulk update failed", error);
      toast.error(error.message || "Failed to update posts");
    } finally {
      setBulkUpdating(false);
    }
  };

  // Columns
  const columns = useMemo(
    () => [
      { key: "post_code", header: "Code", sortable: true },
      { key: "post_name", header: "Name (EN)", sortable: true },
      {
        key: "component",
        header: "OSC",
        className: "text-center",
        render: (_, row) => row.component?.component_name || "-",
      },
      {
        key: "hub",
        header: "Hub",
        className: "text-center",
        render: (_, row) => row.hub?.hub_name || "-",
      },
      {
        key: "total_positions",
        header: "Positions",
        className: "text-center",
        render: (_, row) => `${row.total_positions || 0}`,
      },
      {
        key: "amount",
        header: "Amount",
        className: "text-center",
        render: (_, row) => {
          const amount = row.amount;
          if (amount && amount > 0) {
            return `₹${Number(amount).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
          }
          return "-";
        },
      },
      {
        key: "gender",
        header: "Gender",
        className: "text-center",
        render: (_, row) => {
          if (row.female_only)
            return (
              <span className="inline-flex items-center rounded-full px-2 py-1 text-xs font-medium bg-pink-50 text-pink-700">
                Female Only
              </span>
            );
          if (row.male_only)
            return (
              <span className="inline-flex items-center rounded-full px-2 py-1 text-xs font-medium bg-blue-50 text-blue-700">
                Male Only
              </span>
            );
          return (
            <span className="inline-flex items-center rounded-full px-2 py-1 text-xs font-medium bg-slate-50 text-slate-700">
              All
            </span>
          );
        },
      },
      {
        key: "is_active",
        header: "Status",
        className: "text-center",
        render: (_, row) => (
          <span
            className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}
          >
            {row.is_active ? "Active" : "Inactive"}
          </span>
        ),
      },
      {
        key: "actions",
        header: "Actions",
        className: "text-center",
        render: (_value, row, helpers) => {
          const handleReopen = async () => {
            if (!window.confirm(`Are you sure you want to reopen post "${row.post_name}" for a new recruitment cycle?\n\nThis will:\n• Reset filled positions to 0\n• Make the post active again\n• Allow new applications\n\nNote: Previously selected candidates will remain selected.`)) {
              return;
            }

            try {
              const toastId = toast.loading('Reopening post...');
              await reopenPost(row.post_id, {
                resetFilledPositions: true,
                clearApplications: false
              });
              toast.success('Post reopened successfully!', { id: toastId });
              fetchPosts(); // Refresh the list
            } catch (error) {
              toast.error(error.message || 'Failed to reopen post', { id: toastId });
            }
          };

          const handleClose = async () => {
            if (!window.confirm(`Are you sure you want to close post "${row.post_name}"?\n\nThis will prevent new applications but keep existing ones.`)) {
              return;
            }

            try {
              const toastId = toast.loading('Closing post...');
              await closePost(row.post_id);
              toast.success('Post closed successfully!', { id: toastId });
              fetchPosts(); // Refresh the list
            } catch (error) {
              toast.error(error.message || 'Failed to close post', { id: toastId });
            }
          };

          return (
            <div className="flex justify-center gap-1">
              <TableActions
                onView={() => navigate(`/masters/posts/view/${row.post_id}`)}
                onEdit={() => navigate(`/masters/posts/edit/${row.post_id}`)}
                onDelete={() => helpers?.onDelete?.([row])}
                viewPermission="masters.posts.view"
                editPermission="masters.posts.edit"
                deletePermission="masters.posts.delete"
              />
              
              {/* Custom action buttons */}
              {row.is_active ? (
                <Button
                  size="sm"
                  variant="outline"
                  onClick={handleClose}
                  className="text-orange-600 border-orange-200 hover:bg-orange-50"
                  title="Close Post"
                >
                  <X className="h-4 w-4" />
                </Button>
              ) : (
                <Button
                  size="sm"
                  variant="outline"
                  onClick={handleReopen}
                  className="text-green-600 border-green-200 hover:bg-green-50"
                  title="Reopen Post"
                >
                  <RotateCcw className="h-4 w-4" />
                </Button>
              )}
            </div>
          );
        },
      },
    ],
    [navigate],
  );

  return (
    <div className="space-y-6">
      <PageHeader
        title="Posts"
        description="Manage posts master data"
        actionLabel="Add Post"
        onAction={() => navigate("/masters/posts/add")}
        permission="masters.posts.create"
        // extraActions={
        //     selectedPosts.length > 0 && (
        //         <Button
        //             variant="secondary"
        //             onClick={() => setShowBulkUpdate(!showBulkUpdate)}
        //             leftIcon={<CheckSquare className="h-4 w-4" />}
        //         >
        //             Bulk Update ({selectedPosts.length})
        //         </Button>
        //     )
        // }
      />

      {/* Bulk Update Panel */}
      {/* {showBulkUpdate && selectedPosts.length > 0 && (
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 animate-in fade-in slide-in-from-top-2">
                    <div className="flex justify-between items-start mb-4">
                        <h3 className="font-medium text-blue-900">Bulk Update Selected Posts ({selectedPosts.length})</h3>
                        <button onClick={() => setShowBulkUpdate(false)} className="text-blue-500 hover:text-blue-700">
                            <X className="h-4 w-4" />
                        </button>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
                        <div>
                            <label className="block text-xs font-medium text-blue-800 mb-1">Min Qualification</label>
                            <select
                                className="w-full text-sm rounded border-blue-300 focus:ring-blue-500"
                                value={bulkData.min_education_level_id}
                                onChange={(e) => setBulkData(prev => ({ ...prev, min_education_level_id: e.target.value }))}
                            >
                                <option value="">No Change</option>
                                {educationLevels.map(l => (
                                    <option key={l.level_id} value={l.level_id}>{l.level_name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-medium text-blue-800 mb-1">Max Qualification</label>
                            <select
                                className="w-full text-sm rounded border-blue-300 focus:ring-blue-500"
                                value={bulkData.max_education_level_id}
                                onChange={(e) => setBulkData(prev => ({ ...prev, max_education_level_id: e.target.value }))}
                            >
                                <option value="">No Change</option>
                                {educationLevels.map(l => (
                                    <option key={l.level_id} value={l.level_id}>{l.level_name}</option>
                                ))}
                            </select>
                        </div>
                        Category bulk updates disabled while APIs are offline. Preserve block for future reuse.
                        <div>
                            <label className="block text-xs font-medium text-blue-800 mb-1">Allowed Categories</label>
                            <div className="relative group">
                                <div className="h-10 w-full bg-white border border-blue-300 rounded px-2 py-1 overflow-y-auto text-sm">
                                    {categories.map(cat => (
                                        <label key={cat.category_id} className="flex items-center gap-2 cursor-pointer hover:bg-slate-50 p-1 rounded">
                                            <input
                                                type="checkbox"
                                                checked={bulkData.allowed_category_ids.includes(cat.category_id)}
                                                onChange={(e) => {
                                                    const current = bulkData.allowed_category_ids;
                                                    if (e.target.checked) setBulkData(prev => ({ ...prev, allowed_category_ids: [...current, cat.category_id] }));
                                                    else setBulkData(prev => ({ ...prev, allowed_category_ids: current.filter(id => id !== cat.category_id) }));
                                                }}
                                                className="rounded text-blue-600 h-3 w-3"
                                            />
                                            <span className="truncate">{cat.category_name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                        </div>
                       
                    </div>
                    <div className="flex justify-end">
                        <Button
                            size="sm"
                            isLoading={bulkUpdating}
                            onClick={handleBulkUpdate}
                        >
                            Apply Changes
                        </Button>
                    </div>
                </div>
            )}   */}

      <DataTable
        columns={columns}
        data={posts}
        onSearch={setSearchQuery}
        showRowNumbers={true}
        onDelete={executeDelete}
        onSelectionChange={setSelectedPosts}
        pagination={{
          currentPage: page,
          totalPages: totalPages,
          totalItems,
          onPageChange: setPage,
          pageSize: limit,
          onPageSizeChange: (newLimit) => {
            setLimit(newLimit);
            setPage(1);
          },
          pageSizeOptions: [10, 25, 50, 100],
        }}
        isLoading={loading}
        rowKey="post_id"
        headerClassName="bg-slate-900 text-white"
        extraHeaderContent={
          <div className="flex items-center gap-2">
            <span className="text-xs font-semibold uppercase tracking-wide text-slate-600">
              District
            </span>
            <DropdownSearch
              value={selectedDistrict}
              onChange={(e) => {
                setSelectedDistrict(e.target.value);
                setPage(1);
              }}
              options={[
                { id: '', name: 'All Districts' },
                ...districts.map((d) => ({
                  id: d.district_id,
                  name: d.district_name
                }))
              ]}
              placeholder="Select District"
              className="min-w-[200px]"
            />
          </div>
        }
      />
    </div>
  );
};

export default PostList;
