import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { ArrowLeft, Save } from 'lucide-react';
import { Button } from '../../../components/common/Button';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getApplicationStatusById, createApplicationStatus, updateApplicationStatus } from '../../../services/master.service';
import toast from 'react-hot-toast';

const ApplicationStatusForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;
    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);

    const [formData, setFormData] = useState({
        status_code: '',
        status_name: '',
        status_name_mr: '',
        description: '',
        description_mr: '',
        display_order: '',
        is_active: true
    });

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchStatus = async () => {
                setFetching(true);
                try {
                    const data = await getApplicationStatusById(id);
                    setFormData({
                        status_code: data.status_code || '',
                        status_name: data.status_name_en || data.status_name || '',
                        status_name_mr: data.status_name_mr || '',
                        description: data.description_en || data.description || '',
                        description_mr: data.description_mr || '',
                        display_order: data.display_order || '',
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch status', error);
                    toast.error('Failed to load status details');
                    navigate('/masters/application-statuses');
                } finally {
                    setFetching(false);
                }
            };
            fetchStatus();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.status_code || !formData.status_name) {
            toast.error('Code and Name are required');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            if (payload.display_order) payload.display_order = Number(payload.display_order);

            if (isEditMode) {
                await updateApplicationStatus(id, payload);
                toast.success('Status updated successfully');
            } else {
                await createApplicationStatus(payload);
                toast.success('Status created successfully');
            }
            navigate('/masters/application-statuses');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save status');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) return <div className="p-8 text-center text-slate-500">Loading...</div>;

    return (
        <div className="max-w-2xl mx-auto space-y-6">
            <div className="flex items-center gap-4">
                <Button variant="ghost" onClick={() => navigate('/masters/application-statuses')} leftIcon={<ArrowLeft className="h-4 w-4" />}>Back</Button>
                <h1 className="text-2xl font-bold text-slate-900">{isViewMode ? 'View Status' : isEditMode ? 'Edit Status' : 'Add New Status'}</h1>
            </div>
            <div className="bg-white rounded-lg shadow border border-slate-200 p-6">
                <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid gap-6">
                        <Input label="Status Code" value={formData.status_code} onChange={(e) => setFormData(prev => ({ ...prev, status_code: e.target.value }))} placeholder="DRAFT" required disabled={isViewMode || isEditMode} />
                        <TransliteratedInput
                            label="Status Name"
                            value={formData.status_name}
                            onChange={(e) => setFormData(prev => ({ ...prev, status_name: e.target.value }))}
                            valueMr={formData.status_name_mr}
                            onChangeMr={(e) => setFormData(prev => ({ ...prev, status_name_mr: e.target.value }))}
                            placeholder="Draft"
                            placeholderMr="मसुदा"
                            required
                            disabled={isViewMode}
                        />
                        <Input label="Display Order" type="number" value={formData.display_order} onChange={(e) => setFormData(prev => ({ ...prev, display_order: e.target.value }))} placeholder="1" disabled={isViewMode} />
                        <TransliteratedInput
                            label="Description"
                            value={formData.description}
                            onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                            valueMr={formData.description_mr}
                            onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                            placeholder="Enter description..."
                            placeholderMr="मराठी वर्णन"
                            isTextArea
                            disabled={isViewMode}
                        />
                        <div className="flex items-center gap-2">
                            <input type="checkbox" id="is_active" checked={formData.is_active} onChange={(e) => setFormData(prev => ({ ...prev, is_active: e.target.checked }))} className="rounded border-slate-300 text-blue-600 focus:ring-blue-500 h-4 w-4" disabled={isViewMode} />
                            <label htmlFor="is_active" className="text-sm font-medium text-slate-700">Active Status</label>
                        </div>
                    </div>
                    {!isViewMode && (
                        <div className="flex items-center justify-end gap-4 pt-4 border-t border-slate-200">
                            <Button type="button" variant="outline" onClick={() => navigate('/masters/application-statuses')}>Cancel</Button>
                            <Button type="submit" isLoading={loading} leftIcon={<Save className="h-4 w-4" />}>{isEditMode ? 'Update' : 'Create'}</Button>
                        </div>
                    )}
                </form>
            </div>
        </div>
    );
};

export default ApplicationStatusForm;
