import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import DropdownSearch from '../../../components/common/DropdownSearch';
import { getSchemes, deleteScheme, getDistricts, getSchemeTypes } from '../../../services/master.service';
import toast from 'react-hot-toast';

const SchemeList = () => {
    const navigate = useNavigate();
    const [schemes, setSchemes] = useState([]);
    const [districts, setDistricts] = useState([]);
    const [schemeTypes, setSchemeTypes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [filterDistrict, setFilterDistrict] = useState('');
    const [filterSchemeType, setFilterSchemeType] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchSchemes = useCallback(async () => {
        setLoading(true);
        try {
            const params = { page, limit, search: searchQuery, include_inactive: true };
            if (filterDistrict) params.district_id = filterDistrict;
            if (filterSchemeType) params.scheme_type_id = filterSchemeType;
            const response = await getSchemes(params);
            setSchemes(response.schemes || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? 0);
        } catch (err) {
            toast.error(err.message || 'Failed to load schemes');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery, filterDistrict, filterSchemeType]);

    useEffect(() => {
        fetchSchemes();
    }, [fetchSchemes]);

    useEffect(() => {
        getDistricts({ is_active: true })
            .then(res => setDistricts(res.districts || res || []))
            .catch(() => {});
        getSchemeTypes({ is_active: true })
            .then(res => setSchemeTypes(res.schemeTypes || res || []))
            .catch(() => {});
    }, []);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;
        try {
            const ids = items.map(item => item.scheme_id);
            await Promise.all(ids.map(id => deleteScheme(id)));
            toast.success('Scheme(s) deleted successfully');
            fetchSchemes();
        } catch (error) {
            toast.error(error.message || 'Failed to delete scheme');
        }
    };

    const columns = useMemo(
        () => [
            { key: 'scheme_code', header: 'Scheme Code', sortable: true },
            { key: 'scheme_name', header: 'Scheme Name (EN)', sortable: true },
            { key: 'scheme_name_mr', header: 'Scheme Name (MR)', sortable: true },
            {
                key: 'scheme_type',
                header: 'Scheme Type',
                sortable: false,
                render: (_, row) => row.schemeType?.scheme_name || row.scheme_type?.scheme_name || '—'
            },
            {
                key: 'district',
                header: 'District',
                sortable: false,
                render: (_, row) => row.district?.district_name || '—'
            },
            {
                key: 'is_active',
                header: 'Status',
                render: (_, row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (_value, row, helpers) => (
                    <TableActions
                        onView={() => navigate(`/masters/schemes/view/${row.scheme_id}`)}
                        onEdit={() => navigate(`/masters/schemes/edit/${row.scheme_id}`)}
                        onDelete={() => helpers?.onDelete?.()}
                        viewPermission="masters.schemes.view"
                        editPermission="masters.schemes.edit"
                        deletePermission="masters.schemes.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Schemes"
                description="Manage schemes master data"
                actionLabel="Add Scheme"
                onAction={() => navigate('/masters/schemes/add')}
                permission="masters.schemes.create"
            />

            <div className="flex flex-wrap gap-3 px-1">
                <div className="w-52">
                    <DropdownSearch
                        value={filterDistrict}
                        onChange={(e) => { setFilterDistrict(e.target.value); setPage(1); }}
                        options={districts.map(d => ({ id: d.district_id, name: d.district_name }))}
                        placeholder="Filter by District"
                    />
                </div>
                <div className="w-52">
                    <DropdownSearch
                        value={filterSchemeType}
                        onChange={(e) => { setFilterSchemeType(e.target.value); setPage(1); }}
                        options={schemeTypes.map(t => ({ id: t.scheme_type_id, name: t.scheme_name }))}
                        placeholder="Filter by Scheme Type"
                    />
                </div>
            </div>

            <DataTable
                columns={columns}
                data={schemes}
                onSearch={(val) => { 
    if (val !== searchQuery) {
        setSearchQuery(val); 
        setPage(1); 
    }
}}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages: totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="scheme_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default SchemeList;
