import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input } from '../../../components/common/Input';
import { TransliteratedInput } from '../../../components/common/TransliteratedInput';
import { getExperienceDomainById, createExperienceDomain, updateExperienceDomain, getDocumentTypes } from '../../../services/master.service';
import toast from 'react-hot-toast';
import ToggleSwitch from '../../../components/common/ToggleSwitch';
import { Briefcase } from 'lucide-react';
import FormLayout from '../../../components/common/FormLayout';

const ExperienceDomainForm = ({ isViewMode = false }) => {
    const navigate = useNavigate();
    const { id } = useParams();
    const isEditMode = !!id;
    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(isEditMode || isViewMode);
    const [documentTypes, setDocumentTypes] = useState([]);

    const [formData, setFormData] = useState({
        domain_code: '',
        domain_name: '',
        domain_name_mr: '',
        description: '',
        description_mr: '',
        display_order: '',
        document_type_id: '',
        is_active: true
    });

    useEffect(() => {
        const fetchDocumentTypes = async () => {
            try {
                const response = await getDocumentTypes({ include_inactive: false });
                setDocumentTypes(response.documentTypes || []);
            } catch (error) {
                console.error('Failed to fetch document types', error);
                toast.error('Failed to load document types');
            }
        };
        fetchDocumentTypes();
    }, []);

    useEffect(() => {
        if (isEditMode || isViewMode) {
            const fetchExperienceDomain = async () => {
                setFetching(true);
                try {
                    const data = await getExperienceDomainById(id);
                    setFormData({
                        domain_code: data.domain_code || '',
                        domain_name: data.domain_name || '',
                        domain_name_mr: data.domain_name_mr || '',
                        description: data.description || '',
                        description_mr: data.description_mr || '',
                        display_order: data.display_order || '',
                        document_type_id: data.doc_type_id || '', // Backend uses doc_type_id
                        is_active: data.is_active
                    });
                } catch (error) {
                    console.error('Failed to fetch experience domain', error);
                    toast.error('Failed to load experience domain details');
                    navigate('/masters/experience-domains');
                } finally {
                    setFetching(false);
                }
            };
            fetchExperienceDomain();
        }
    }, [id, isEditMode, isViewMode, navigate]);

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!formData.domain_code || !formData.domain_name) {
            toast.error('Code and Name are required');
            return;
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            if (payload.display_order) payload.display_order = Number(payload.display_order);

            // Convert doc_type_id: empty string to null, otherwise to number
            if (payload.document_type_id === '' || payload.document_type_id === null) {
                payload.doc_type_id = null;
            } else {
                payload.doc_type_id = Number(payload.document_type_id);
            }
            delete payload.document_type_id; // Remove the frontend field name

            if (isEditMode) {
                await updateExperienceDomain(id, payload);
                toast.success('Experience domain updated successfully');
            } else {
                await createExperienceDomain(payload);
                toast.success('Experience domain created successfully');
            }
            navigate('/masters/experience-domains');
        } catch (error) {
            console.error('Save failed', error);
            toast.error(error.message || 'Failed to save experience domain');
        } finally {
            setLoading(false);
        }
    };

    if (fetching) return <div className="p-8 text-center text-slate-500">Loading...</div>;

    return (
        <FormLayout
            title="Experience Domain"
            icon={Briefcase}
            onSubmit={handleSubmit}
            onCancel={() => navigate('/masters/experience-domains')}
            isEditMode={isEditMode}
            isViewMode={isViewMode}
            loading={loading}
        >
            <Input
                label="Domain Code"
                value={formData.domain_code}
                onChange={(e) => setFormData(prev => ({ ...prev, domain_code: e.target.value }))}
                placeholder="WOMEN_RELATED"
                required
                disabled={isViewMode || isEditMode}
            />
            <TransliteratedInput
                label="Domain Name"
                value={formData.domain_name}
                onChange={(e) => setFormData(prev => ({ ...prev, domain_name: e.target.value }))}
                valueMr={formData.domain_name_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, domain_name_mr: e.target.value }))}
                placeholder="Women Related Domain"
                placeholderMr="महिला संबंधित क्षेत्र"
                disabled={isViewMode}
                required
            />
            <TransliteratedInput
                label="Description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                valueMr={formData.description_mr}
                onChangeMr={(e) => setFormData(prev => ({ ...prev, description_mr: e.target.value }))}
                placeholder="Experience in women empowerment..."
                placeholderMr="महिला सक्षमीकरण..."
                isTextArea={true}
                disabled={isViewMode}
            />

           <ToggleSwitch
                label="Active Status"
                description={formData.is_active ? 'Experience domain is currently active' : 'Experience domain is currently inactive'}
                checked={formData.is_active}
                onChange={(val) => setFormData(prev => ({ ...prev, is_active: val }))}
                disabled={isViewMode}
                />
        </FormLayout>
    );
};

export default ExperienceDomainForm;