import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { DataTable } from '../../../components/ui/DataTable';
import { PageHeader } from '../../../components/common/PageHeader';
import { TableActions } from '../../../components/common/TableActions';
import { getSkills, deleteSkill } from '../../../services/master.service';
import toast from 'react-hot-toast';

const SkillList = () => {
    const navigate = useNavigate();
    const [skills, setSkills] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [page, setPage] = useState(1);
    const [limit, setLimit] = useState(10);
    const [totalPages, setTotalPages] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    const fetchSkills = useCallback(async () => {
        setLoading(true);
        try {
            const response = await getSkills({
                page,
                limit,
                search: searchQuery,
                include_inactive: true
            });
            setSkills(response.skills || []);
            setTotalPages(response.pagination?.totalPages || 1);
            setTotalItems(response.pagination?.total ?? response.pagination?.totalItems ?? 0);
        } catch (err) {
            console.error('Failed to fetch skills', err);
            toast.error(err.message || 'Failed to load skills');
        } finally {
            setLoading(false);
        }
    }, [page, limit, searchQuery]);

    useEffect(() => {
        fetchSkills();
    }, [fetchSkills]);

    const handleDelete = async (items) => {
        if (!items || items.length === 0) return;

        try {
            const ids = items.map(item => item.skill_id);
            await Promise.all(ids.map(id => deleteSkill(id)));
            toast.success('Skill(s) deleted successfully');
            fetchSkills();
        } catch (error) {
            console.error('Delete failed', error);
            toast.error(error.message || 'Failed to delete skill');
        }
    };

    const columns = useMemo(
        () => [
            { key: 'skill_name_en', header: 'Name (EN)', sortable: true, render: (_, row) => row.skill_name_en || row.skill_name },
            { key: 'skill_name_mr', header: 'Name (MR)', sortable: true },
            { key: 'description', header: 'Description (EN)', sortable: false },
            { key: 'description_mr', header: 'Description (MR)', sortable: false },
            {
                key: 'is_active',
                header: 'Status',
                render: (_, row) => (
                    <span className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-medium ${row.is_active ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                        {row.is_active ? 'Active' : 'Inactive'}
                    </span>
                )
            },
            {
                key: 'actions',
                header: 'Actions',
                render: (_value, row, helpers) => (
                    <TableActions
                        onView={() => navigate(`/masters/skills/view/${row.skill_id}`)}
                        onEdit={() => navigate(`/masters/skills/edit/${row.skill_id}`)}
                        onDelete={() => helpers?.onDelete?.()}
                        viewPermission="masters.skills.view"
                        editPermission="masters.skills.edit"
                        deletePermission="masters.skills.delete"
                    />
                ),
            },
        ],
        [navigate]
    );

    return (
        <div className="space-y-6">
            <PageHeader
                title="Skills"
                description="Manage skills master data"
                actionLabel="Add Skill"
                onAction={() => navigate('/masters/skills/add')}
                permission="masters.skills.create"
            />

            <DataTable
                columns={columns}
                data={skills}
                onSearch={setSearchQuery}
                showRowNumbers={true}
                onDelete={handleDelete}
                pagination={{
                    currentPage: page,
                    totalPages,
                    totalItems,
                    onPageChange: setPage,
                    pageSize: limit,
                    onPageSizeChange: (newLimit) => {
                        setLimit(newLimit);
                        setPage(1);
                    },
                    pageSizeOptions: [10, 25, 50, 100]
                }}
                isLoading={loading}
                rowKey="skill_id"
                headerClassName="bg-slate-900 text-white"
            />
        </div>
    );
};

export default SkillList;
